window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q04"]=window.__LIBQ["the-gioi-hoan-my"]["q04"]||{};window.__LIBQ["the-gioi-hoan-my"]["q04"]["cotTruyen"]=[{"chuong":301,"tieuDe":"Cường Thế Thẳng Tiến","tomTat":"Thạch Hạo phong tỏa sân nhỏ trong khách sạn Hổ Môn, hợp nhất với người tí hon màu đen thành Bất Diệt Kim Thân rồi quét sạch các cường giả đang chống trả. Khi Thạch Tử Minh dẫn người của Võ Vương phủ và kỵ binh Vũ tộc tới tiếp viện, họ chỉ kịp chứng kiến Vũ Mục bị Thạch Hạo ép vùi xuống đất và giết chết. Trước sự vây công của đối phương, Thạch Hạo mở mười tòa Động Thiên cố định những kẻ cầm đầu, chém đầu Thạch Tử Minh cùng nhiều cao thủ rồi tiêu diệt các tử sĩ còn ngoan cố. Không hề có ý định lẩn trốn, hắn tuyên bố sẽ chủ động tới tận Vũ tộc đòi lời giải thích, sau đó vận dụng tàn pháp Côn Bằng bay ngang Hoàng Đô và vượt trước cả những kỵ binh đang chạy về báo tin. Đứng trước phủ đệ Vũ tộc, Thạch Hạo nhớ lại việc gia đình mình từng bị truy sát, Thạch Tử Lăng bị pháp chỉ Thần Linh làm trọng thương và Thanh Phong bị hãm hại, khiến quyết tâm thanh toán nợ cũ càng thêm mãnh liệt. Bị lính canh xua đuổi, hắn tung ra một bàn tay lớn màu đen, xuyên phá sự bảo vệ của đại trận và đánh sập cửa chính cùng hàng loạt kiến trúc lân cận, làm chấn động cả khu phố."},{"chuong":302,"tieuDe":"Bát Hung Kiếm","tomTat":"Thạch Hạo tới Vũ Vương phủ, đánh sập cửa chính cùng một phần tường viện và dễ dàng chấn văng nhóm hộ vệ ngăn đường. Tại tiền viện, các cao thủ Vũ tộc dùng tám thanh phi kiếm tạo thành Bát Hung kiếm trận, khiến sức mạnh và kiếm quang tầng tầng chồng chất. Không tiếp tục đối đầu trực diện, Thạch Hạo mở mười Động Thiên hút toàn bộ phi kiếm vào trong, sau đó dùng sấm sét tím khiến những người điều khiển kiếm trận mất khả năng chiến đấu. Nó biết bộ kiếm hiện tại được làm từ phù cốt của tám loại di chủng, còn bản Thượng Cổ chân chính cần nguyên thủy phù cốt của chim thần và hung thú thuần huyết trưởng thành. Khi phát hiện thần chú trên hộp đá có thể đóng vai trò trận đồ, Thạch Hạo dự định sau này tìm đủ tám khối phù cốt Thái Cổ để tái luyện Bát Hung kiếm trận chân chính rồi lập tức tế luyện chiến lợi phẩm."},{"chuong":303,"tieuDe":"Đại Náo Vũ Vương Phủ","tomTat":"Thạch Hạo mang danh nghĩa tới tặng lễ cho Vũ tộc, đúng lúc kỵ binh trở về báo tin Vũ Mục cùng toàn bộ đầu lĩnh tham gia vây giết nó tại khách sạn Hổ Môn đã tử trận, khiến Vũ tộc mất hết thể diện trước các tu sĩ Hoàng Đô. Bốn chiến tướng lập tức dùng cuồng phong, mưa gió và sấm chớp vây công, nhưng Thạch Hạo triệu hồi Toan Nghê màu tím, lợi dụng chính màn mưa để khuếch tán lôi điện và trấn áp cả bốn. Nó tiếp tục dùng sức kéo đứt Lưới Khốn Tiên rồi vận chuyển kiếm trận tám thanh phi kiếm, chém tan đội kỵ binh cùng hàng loạt cường giả trước cửa phủ. Khi Vũ tộc dựng đại trận phòng thủ, Thạch Hạo dung hợp Bất Diệt Kim Thân, bẻ gãy hơn mười đại kỳ và xông thẳng vào Vũ Vương phủ. Dù bị các trưởng bối thu vào bảo tháp để luyện hóa, nó vẫn phá nổ pháp khí từ bên trong, khiến mảnh vỡ bắn trọng thương nhiều người. Sau khi san bằng sân viện, cung điện và lầu các thành phế tích, Thạch Hạo bỏ lớp che giấu, để lộ chân dung thật khiến toàn bộ người Vũ tộc kinh hãi nhận ra nó."},{"chuong":304,"tieuDe":"Vũ Đạo Cửu Trùng Thiên","tomTat":"Nhận ra Thạch Hạo chính là Hùng Hài Tử từng khiến họ tổn thất nặng nề ở Bách Đoạn Sơn và Hư Thần giới, người Vũ tộc lập tức hợp lực vây giết nó. Thạch Hạo cũng nhắc lại những món nợ máu mà Vũ tộc đã gây ra cho gia đình mình và Bổ Thiên các, khẳng định mối thù giữa hai bên không thể hóa giải. Đông đảo cao thủ Vũ tộc thi triển Vũ Đạo Cửu Trùng Thiên, biến phủ đệ thành biển nước và liên tiếp tạo ra những đóa sen có uy lực tăng dần để phong tỏa mọi đường lui. Thạch Hạo vận dụng bảo thuật Côn Bằng cùng cảnh giới Hóa Linh viên mãn để hấp thu thần năng, đồng thời dùng kiếm gãy màu đen phá tan các tầng công kích, giết nhiều đối thủ và hủy hoại năm lớp sân viện. Lượng tinh khí khổng lồ được luyện hóa khiến quanh nó xuất hiện thần quang, người tí hon bằng phù văn, bóng Thần Ma và một đám mây vàng có khả năng nâng nó phi hành. Khi hoa sen tầng thứ tám hiện ra, uy thế kinh động các vương hầu trong Hoàng Đô, nhưng Thạch Hạo vẫn tiếp tục nuốt lấy lực lượng của đối phương. Đến lúc cơ thể gần nổ tung vì thần năng quá tải, nó hóa thành một luồng sáng rực rỡ, lao thẳng vào hoa sen và toàn bộ đội hình Vũ tộc để phản công."},{"chuong":305,"tieuDe":"Ảnh Chiếu Vũ Thần","tomTat":"Thạch Hạo vận chuyển bảo thuật Côn Bằng, điều động hàng loạt binh khí phù văn phá tan đóa sen thứ tám của Vũ tộc, dù bản thân cũng bị chấn thương. Sau khi điều tức, nó cầm kiếm gãy xông vào đội hình đối phương, chém chết vài người, nhưng bảo thuật Vũ tộc vẫn tự ngưng tụ đóa sen thứ chín cấm kỵ. Đóa sen triệu gọi một hình chiếu Vũ Thần từ ngoài Hoang Vực, khiến người Vũ tộc cuồng nhiệt tin rằng tổ tiên của họ vẫn còn sống. Trước thần uy khiến mình liên tiếp ho ra máu, Thạch Hạo dung hợp Bất Diệt Kim Thân, bí mật gia trì lực Côn Bằng lên kiếm gãy để nghịch chiến. Dù bị đánh bay và trọng thương, nó vẫn phá nổ một cánh tay của hình chiếu Vũ Thần, làm Vũ tộc hoảng loạn và khiến các vương hầu nghi ngờ bản thể vị thần đang ở trong tình trạng bất ổn. Sau khi nhai linh dược hồi phục, Thạch Hạo tiếp tục dốc toàn lực chém đòn tối hậu, đúng lúc hình chiếu Vũ Thần lay động và dường như sắp mở mắt."},{"chuong":306,"tieuDe":"Đến Tột Cùng Là Người Nào","tomTat":"Thạch Hạo dốc toàn lực chống lại bàn tay khổng lồ của hình chiếu Vũ Thần, trong khi kiếm gãy tự hóa thành Hắc Long quấn lấy đòn công kích, khiến bóng thần mất ổn định rồi tan thành mưa sáng. Sau khi uống rượu Hầu Nhi để chữa thương, cậu vung kiếm chém ngang hơn mười người Vũ tộc đang nhân cơ hội vây giết, làm những kẻ còn lại khiếp sợ không dám tiến lên. Từ kiếm gãy và những chiến tích tại Hư Thần giới, đám đông nhận ra cậu chính là Hùng Hài Tử từng mở mười Động Thiên, khiến tin tức nhanh chóng chấn động Hoàng Đô. Trước lời quát mắng của các cường giả Vũ tộc vừa xuất quan, Thạch Hạo thẳng thừng vạch lại lỗi lầm của họ rồi tung một chưởng phá hủy hàng loạt cung điện, lâm viên và sân viện trong phủ. Các trưởng bối và lão tổ Vũ tộc nhận thấy dung mạo cậu giống Thạch Tử Lăng, lại mang thần vận của Đại Ma Thần, nên nghi ngờ cậu chính là đứa trẻ năm xưa mà họ tưởng đã chết. Thạch Hạo không thừa nhận cũng không phủ nhận, bình thản để họ dùng Kính Thấu Cốt soi xét, và người điều khiển bảo kính lập tức kinh hãi xác nhận cậu chính là người mà Vũ tộc lo sợ."},{"chuong":307,"tieuDe":"Phân Rõ Ra","tomTat":"Vũ tộc dùng kính Thấu Cốt xác nhận Thạch Hạo chính là đứa trẻ từng bị cướp Chí Tôn cốt, đồng thời kinh hãi phát hiện trong ngực hắn đang thai nghén một khối Chí Tôn cốt mới sau lần niết bàn. Lo sợ tiềm lực của hắn sẽ vượt khỏi khả năng khống chế, các trưởng bối lập tức khởi động cổ trận gồm biển đồng, cốt đăng và ba mươi sáu chiến mâu để diệt trừ hậu họa. Thạch Hạo dùng kiếm gãy phá trận văn, thi triển Đào Uyển chống đỡ rồi dựng kiếm trận Bát Hung phá tan đại trận, sau đó dùng chén Hóa Thiên nghiền nát những pháp khí còn lại. Khi biết Tế Linh đã rời phủ từ nhiều ngày trước, Vũ tộc buộc phải kích hoạt pháp chỉ Vũ Thần được cất giữ trong ngôi miếu cổ. Tiểu tháp chủ động trợ giúp để đoạt dấu ấn tinh thần của Thần Linh trên pháp chỉ, đồng thời khiến một mảnh giấy vàng dung hợp với Bất Diệt Kim Thân của Thạch Hạo nhằm chữa trị nó. Cảm thấy tiểu tháp và Bất Diệt Kim Thân đều thu được lợi ích còn mình thì không, Thạch Hạo gỡ mảnh pháp chỉ đã ảm đạm xuống rồi thản nhiên nhai nuốt, khiến những nhân vật trọng yếu của Vũ tộc kinh hãi tột độ."},{"chuong":308,"tieuDe":"Pháp Chỉ Thê Thảm","tomTat":"Thạch Hạo ngang nhiên gặm pháp chỉ Thần Linh trước Vũ Vương phủ, đồng thời dùng chén sứ luyện hóa những kẻ Vũ tộc lao ra truy sát. Không chịu nổi sự sỉ nhục, lão tổ Vũ tộc ra lệnh ghép các mảnh pháp chỉ và tế đại sát khí, khiến thần uy cùng xích thần trật tự trấn áp cả khu vực. Tuy nhiên, tiểu tháp âm thầm hóa giải sát cơ rồi chia pháp chỉ thành nhiều phần: nó nuốt phần lớn, chiến y màu đen hấp thu một phần, còn Thạch Hạo ăn một mảnh và giữ lại một mảnh để dùng khi tiến vào Minh Văn cảnh. Pháp chỉ truyền thừa sau nhiều lần bị cướp chỉ còn khoảng một nửa, nhưng tiểu tháp không lấy sạch vì lo tiếp tục can thiệp sẽ phá vỡ một sự cân bằng đáng sợ. Khi người Vũ tộc rời đại trận truy kích, Thạch Hạo dùng kiếm gãy chém chết nhiều kẻ, trong đó có một trưởng bối quan trọng, rồi công khai cảnh cáo cả tộc phải an phận nếu muốn tồn tại. Nó vận dụng bảo thuật Côn Bằng rời đi, dành cơ hội đại sát phạt của tiểu tháp cho Thái Cổ Ma Chu. Biết Vũ tộc chắc chắn sẽ báo tin cho phe Thạch Tử Đằng, Thạch Hạo quyết định chủ động tới tận nơi, công khai thân phận thật và đón một đứa trẻ từng để lại cho mình ấn tượng tốt đẹp."},{"chuong":309,"tieuDe":"Một Mình Tiến Vào Võ Vương Phủ","tomTat":"Nhớ lại quãng thời gian bị mất Chí Tôn cốt và chỉ có A Man tận tình chăm sóc, Thạch Hạo quyết định trở về Võ Vương phủ để đón nàng đi. Giữa lúc Hoàng Đô còn chấn động vì chiến tích nó phá Vũ Vương phủ và ăn pháp chỉ Vũ Thần, Thạch Hạo một mình tới nơi mình chào đời, khiến đám thủ vệ kinh hãi khi nhận ra vị khách chính là thiếu niên hung danh lẫy lừng. Lo người trong phủ báo tin cho Thạch Tử Đằng, nó tự ý rời đại sảnh và lần theo ký ức tìm đến tiểu viện của A Man. Tại đây, một thiếu nữ cho biết A Man có thiên tư phi phàm, từng được bí mật bồi dưỡng như nội tình của gia tộc và đã được Thập Ngũ gia đưa khỏi phủ từ lâu, nhưng không ai rõ họ đang ở đâu. Khi Thạch Hạo trở lại đại điện, Võ Vương phủ đã náo loạn như gặp đại địch, còn phe Thạch Tử Đằng và nhóm lão nhân đối lập đều kéo đến chất vấn. Trước mặt tất cả mọi người, thiếu niên đường đường chính chính xưng tên Thạch Hạo, khiến lời tuyên bố vang khắp Võ Vương phủ và truyền ra ngoài."},{"chuong":310,"tieuDe":"Ta Tên Thạch Hạo","tomTat":"Thạch Hạo công khai danh tính tại Võ Vương phủ, khiến những người biết chuyện năm xưa chấn động khi đứa trẻ từng bị cho là đã chết nay sống sót trở về. Nhất mạch Thạch Tử Đằng lập tức vu cho cậu giả mạo và định bắt giữ, nhưng các lão huynh đệ của Thập Ngũ gia dựa vào dung mạo giống Thạch Tử Lăng cùng Đại Ma Thần để xác nhận thân phận của cậu. Trước hai phe đang đối đầu, Thạch Hạo thừa nhận mình vừa phá hủy Vũ Vương phủ để đòi món nợ mà Vũ tộc đã gây ra. Khi Thạch Trung Hòa tỏ ý ban cho cậu cơ hội nhận tổ quy tông, Thạch Hạo thẳng thừng từ chối, tuyên bố quan hệ giữa mình và Võ Vương phủ đã chấm dứt từ ngày cha cậu bị xua đuổi. Cậu sau đó vạch trần mình vốn là Chí Tôn trời sinh, nhưng Chí Tôn cốt đã bị móc khỏi cơ thể lúc còn nhỏ rồi cấy cho Thạch Nghị, và mục đích trở về là buộc những kẻ liên quan đưa ra lời giải thích. Chân tướng bị phong tỏa suốt nhiều năm nhanh chóng truyền khắp Hoàng Đô, tạo thành cơn chấn động lớn và đẩy Võ Vương phủ vào một cuộc đối chất không thể né tránh."},{"chuong":311,"tieuDe":"Chiêu Cáo Với Thiên Hạ","tomTat":"Thân phận Thạch Hạo chính là Hùng Hài Tử lừng danh Hư Thần giới được công khai, khiến Hoàng Đô chấn động và bí mật về đứa trẻ trời sinh Chí Tôn của Võ Vương phủ bị phơi bày. Trước những lời khuyên hắn gác bỏ thù cũ vì lợi ích gia tộc, Thạch Hạo vạch trần việc Chí Tôn cốt của mình từng bị móc đi, phụ thân bị trục xuất, cả nhà bị Vũ tộc phối hợp truy sát đến Tây Cương, còn tổ phụ cũng bị ngăn cản điều tra. Hắn tuyên bố chuyến đi này nhằm chiêu cáo thiên hạ rằng mình vẫn còn sống, để phụ mẫu và tổ phụ có thể nhận được tin, đồng thời khẳng định dù mất Chí Tôn cốt vẫn đủ sức tung hoành. Khi hòa giải thất bại, Thạch Hạo khiêu chiến Thạch Tử Đằng, nhưng Thạch Trung Hòa đứng ra thăm dò trước và dùng đại trận xương thú vây nhốt hắn. Thạch Hạo hợp nhất với Bất Diệt Kim Thân, vận dụng Kiếm trận Bát Hung phá trận, rồi dùng chén Hóa Thiên bắt giữ và phế bỏ toàn bộ tu vi của Thạch Trung Hòa nhưng tha mạng cho ông ta chứng kiến cuộc đối đầu tương lai giữa mình với kẻ được tôn là trời sinh thần nhân. Sau đó, Thạch Hạo gọi Thạch Tử Đằng ra chiến, còn vị đại bá này chấp nhận luận bàn và lập tức lao tới, chính thức mở màn cuộc giao phong."},{"chuong":312,"tieuDe":"Chiến Thạch Tử Đằng","tomTat":"Thạch Hạo và Thạch Tử Đằng bước vào võ trường được trận văn bảo vệ rồi chính thức khai chiến, một bên thi triển Tụ lý càn khôn, bên kia dùng Long Giao tiễn phá tan thế thu giữ. Thạch Tử Đằng liên tiếp vận dụng ba mươi sáu phù kiếm và bảo thuật Kim Ô, nhưng Thạch Hạo lần lượt hóa Huyền Vũ phòng ngự, dùng Toan Nghê đối kháng rồi dựa vào Bất Diệt Kim Thân giao phong trực diện mà không hề chịu thương tổn. Khi Thạch Tử Đằng hóa thành Thiên Hạc tấn công, Thạch Hạo vận dụng áo nghĩa Côn Bằng áp chế đối thủ, đánh hắn bay ngang và chảy máu nơi khóe miệng. Mang sát tâm vì không muốn xuất hiện thêm một Chí Tôn bên cạnh Thạch Nghị, Thạch Tử Đằng bất ngờ phóng Chu Ti Phi Tiên ám sát, song Thạch Hạo kịp né tránh nên chỉ bị rạch nhẹ trên má. Thạch Tử Đằng sau đó mặc chiến y kim loại hình nhện, lấy ra Phương Thiên Họa kích đỏ thắm và dễ dàng chém nát chủy thủ mà Thạch Hạo dùng để thử binh khí. Nhận thấy đại kích đúng là binh khí hạng nặng mình đang thiếu, Thạch Hạo công khai tuyên bố muốn đoạt lấy, khiến Thạch Tử Đằng lập tức vung kích giáng xuống với sát khí ngập trời."},{"chuong":313,"tieuDe":"Đánh Bại","tomTat":"Thạch Hạo diễn hóa mười con Toan Nghê cùng biển sét, phá tan bảo thuật Ma Chu và Tụ lý càn khôn của Thạch Tử Đằng. Trước uy lực của Phương Thiên Họa kích từng nhiễm máu rồng, nó dùng Ấn Côn Bằng và chén sứ đã phá phong ấn để đánh tan hình rồng đỏ, chặn đứng mũi kích. Sau khi bị những chân nhện trên chiến y làm bị thương, Thạch Hạo mở mười Động Thiên giam cầm hư không, đồng thời vận chuyển cốt văn theo Nguyên Thủy Chân Giải để hòa vào nhịp đập của thiên địa. Nhờ đó, nó áp chế Thạch Tử Đằng, đoạt lấy Long Huyết Chiến kích và xóa bỏ dấu ấn của chủ nhân cũ. Thạch Tử Đằng phát cuồng, huy động linh thân, bảo thuật và chiến y Ma Chu tái chiến, nhưng vẫn bị Thạch Hạo dùng chính đại kích phá nát mọi thủ đoạn rồi đánh mạnh xuống đất. Khi mọi người xác nhận Thạch Tử Đằng đã thất bại và Thạch Hạo chuẩn bị tiếp tục ra tay, một luồng ma uy khủng bố bất ngờ bao trùm khiến toàn bộ Võ Vương phủ rung chuyển, báo hiệu Thái Cổ Ma Chu đã giáng lâm."},{"chuong":314,"tieuDe":"Không Thể Chiến Một Trận","tomTat":"Chân thân Thái Cổ Ma Chu giáng xuống Hoàng Đô, dùng thần uy áp chế Thạch Hạo và định giết nó để trừ hậu họa cho hồ Ma Linh. Nhân Hoàng công khai xác nhận Thạch Hạo là người của Thạch tộc, rồi hóa ra vầng thái dương vàng chặn chân nhện khổng lồ đang đánh xuống Võ Vương phủ, buộc Ma Chu nể mặt rút lui và tránh một trận chiến cấp Tôn giả. Thạch Hạo tiếc nuối vì vốn định dụ Ma Chu tới gần để vận dụng tiểu tháp, nhưng nhanh chóng chuyển sự chú ý sang đại thọ Nhân Hoàng, nơi các sinh linh Thái Cổ Thần Sơn có thể tụ hội. Sau khi Thạch Tử Đằng dẫn người rời đi, tin tức Thạch Hạo phá Võ Vương phủ, đoạt chiến kích Huyết Long và thân phận đứa trẻ từng bị lấy mất Chí Tôn cốt lập tức truyền khắp kinh thành. Dư luận vì thế càng mong chờ cuộc quyết đấu giữa Thạch Hạo và Thạch Nghị, kẻ đang sở hữu cả Trùng Đồng, Chí Tôn cốt cùng Bổ Thiên thuật. Thạch Hạo hy vọng tin mình còn sống sẽ đến được với cha mẹ và tổ phụ, rồi nhận lời mời tới Quan Nguyệt lâu gặp linh thân Thiên Hồ tiên tử. Tại đây, Thiên Hồ tiên tử tuyên bố muốn bảo vệ Thạch Hạo và cảnh báo rằng Nguyệt Thiền có thể sẽ gây bất lợi cho nó."},{"chuong":315,"tieuDe":"Song Tiên","tomTat":"Thiên Hồ tiên tử cố ý khích Thạch Hạo tuyên bố sẽ trấn áp Nguyệt Thiền và bắt nàng về Thạch Thôn làm vợ, trong khi Nguyệt Thiền đã âm thầm đứng ngoài cửa nghe rõ mọi chuyện. Thạch Hạo kinh ngạc vì linh giác của mình không phát hiện được nàng, rồi biết Nguyệt Thiền mang theo một bảo vật bí ẩn có thể che giấu hoàn toàn khí thế. Giữa màn đối đáp châm chọc của hai tiên tử, Nguyệt Thiền tiết lộ Bổ Thiên các vốn là một chi nhánh của Bổ Thiên giáo, do một đệ tử bị trục xuất lập nên tại Hoang Vực. Thạch Hạo lập tức liên hệ vị tổ sư ấy với Quỷ gia và lạnh lùng chất vấn vì sao Bổ Thiên giáo không cứu viện khi Bổ Thiên các bị tiêu diệt. Nguyệt Thiền giải thích rằng đại giáo nhận tin quá muộn, đồng thời hứa sẽ thanh toán những món nợ cũ và cảnh báo Hoang Vực sắp rơi vào đại loạn, nơi ngay cả thần thánh cũng khó giữ mạng. Sau đó, Nguyệt Thiền dựa vào quan hệ đồng nguyên để lôi kéo Thạch Hạo về Bổ Thiên giáo, còn Thiên Hồ tiên tử công khai mời nó gia nhập Tiệt Thiên giáo, khiến cuộc tranh chấp giữa hai đạo thống càng thêm gay gắt. Nhận ra lựa chọn bất kỳ phe nào cũng có thể khiến mình bị phe còn lại truy sát, Thạch Hạo khéo léo né tránh bằng cách hỏi liệu nó có thể vừa làm Ma Vương vừa làm Thần Quân hay không."},{"chuong":316,"tieuDe":"Hỗn Thiên","tomTat":"Rời Quan Nguyệt lâu sau màn đối đáp với Ma Nữ và Nguyệt Thiền tiên tử, Thạch Hạo quyết định chuyên tâm tu hành để chuẩn bị cho những cuộc đối đầu khó tránh trong tương lai. Theo lời mời của Hỗn Thiên hầu, nó tới một lâm viên kín đáo uống rượu và được vị vương hầu trẻ tuổi tiết lộ rằng Hoàng Đô cùng toàn Hoang Vực sắp rơi vào đại loạn. Biến động này có liên quan đến một tồn tại hoặc nguyên nhân được gọi là cấm kỵ, đồng thời cơ duyên trợ thành vô thượng Chân Thần tại Hoang Vực cũng sẽ lôi kéo Bổ Thiên giáo, Tiệt Thiên giáo và nhiều thế lực vực ngoại tiến vào. Hỗn Thiên hầu đề nghị hai người cân nhắc hợp tác để chủ động nắm giữ vận mệnh, còn Thạch Hạo chỉ bày tỏ mong muốn được sống trong một thế giới tự do, dù điều đó có thể buộc nó phải trở thành Đại Đế thống trị Hoang Vực. Sau cuộc rượu, Thạch Hạo say đến mức bế nhầm muội muội của Hỗn Thiên hầu, nhưng vẫn ghi nhớ lời cảnh báo về cơn sóng gió sắp tới. Vài ngày sau, nó mang thiệp mời màu vàng vào hoàng cung dự đại thọ Nhân Hoàng, tận mắt thấy Bệ Ngạn trấn giữ cửa cung và đông đảo cường giả liên tục hội tụ, báo hiệu một biến cố khác thường sắp xảy ra."},{"chuong":317,"tieuDe":"Hoàng Cung","tomTat":"Thạch Hạo cùng các cường giả tiến vào hoàng cung Thạch Quốc, nơi quần thể cung điện cổ xưa, sông ngòi, linh dược và vô số linh thú quý hiếm phô bày nội tình thâm hậu của Cổ Quốc. Trong lúc các giáo chủ, vương hầu và sinh linh thuần huyết tề tựu dự đại thọ Nhân Hoàng, nó thản nhiên đi khắp quảng trường, cố ý nhắc lại những thất bại cũ để chọc giận Vũ Phong, Thạch Tử Đằng, Thác Bạc thế gia và Xích Vân công tử. Hỏa Linh Nhi đại diện Hỏa Hoàng đến chúc thọ, vừa trách Thạch Hạo gọi mình bằng biệt danh khó nghe, vừa quan tâm hỏi về chuyến đi Bắc Hải và tin đồn nó đã chết tại tổ Côn Bằng. Sói con Ấu Thần lập tức bỏ nàng để nhảy sang Thạch Hạo, khiến nó kinh ngạc khi phát hiện thần lực trong cơ thể con vật đã tăng mạnh nhưng lại không hề có phù văn để truy tìm nguyên nhân. Sau khi Hỏa Linh Nhi vào trung tâm Thiên cung làm lễ, một nhóm hậu đại trẻ tuổi của Thái Cổ Thần Sơn chủ động tìm đến Thạch Hạo với thái độ không thiện chí. Trước lời chất vấn về danh hiệu thiếu niên hung tàn nhất, Thạch Hạo bình thản thừa nhận thân phận, đồng thời dừng ánh mắt trên thiếu nữ áo tím Vân Hi."},{"chuong":318,"tieuDe":"Bễ Nghễ","tomTat":"Thạch Hạo thản nhiên đối mặt với con cháu các Thái Cổ Thần Sơn, công khai bác bỏ thái độ bề trên của họ, khiến tám chín thiếu niên ôn hòa chủ động đứng ngoài, chỉ còn bốn người tiếp tục gây hấn. Hắn khơi lại ân oán Bắc Hải với Vân Hi và Ngân Tuyết, còn hai thiếu nữ cho rằng cái chết của Thanh Vân đã đủ để kết thúc món nợ cũ; lời đề nghị họ về bảo vệ đầu thôn của hắn lại khiến Vân Hi tức giận vì nhớ đến chuyện tại Bách Đoạn sơn. Lấy cái chết của Thanh Vân làm cớ, nhóm đối địch khiêu chiến Thạch Hạo và được thị vệ trưởng dẫn tới diễn võ trường cạnh Thiên cung, nơi Hoàng tộc đã bố trí trận văn cho những cuộc quyết đấu mừng đại thọ Nhân Hoàng. Thiếu niên tóc xám mắt xám vừa xuất trận đã kích hoạt một Thượng Cổ Thánh khí hoàn chỉnh, tung ra sức mạnh đủ nghiền chết tu sĩ Hóa Linh cảnh, cho thấy đây không còn là cuộc tỷ thí thông thường mà là một vụ tập sát có chuẩn bị. Thạch Hạo không sử dụng kiếm gãy hay tiểu tháp, chỉ vung mạnh cánh tay trái đón lấy chùm sáng hủy diệt. Trong khoảnh khắc ấy, hắn nhận ra phía sau đối thủ có một Tôn giả Thần Sơn cho phép giết mình và âm thầm ghi kẻ đó vào danh sách những kẻ phải thanh toán."},{"chuong":319,"tieuDe":"Cánh Tay Trái Của Thần","tomTat":"Thạch Hạo chủ động đối đầu Thanh Thiên bảo luân, dùng cánh tay trái tỏa khí tức thần thánh và phù văn hộ thể để liên tiếp đánh bật món Thượng Cổ Thánh khí. Mọi người nhận ra trong cánh tay nó dung hợp khí hồn hộ tí của Thiên Thần sơn, pháp khí Thần Linh từng được nó lấy từ Hư Thần giới. Sau nhiều lần thúc giục bảo luân, thiếu niên tóc xám cạn kiệt thần lực và bị Thạch Hạo áp sát đánh gãy nhiều xương; ba đồng bọn bỏ chạy cũng bị mười Động Thiên giam cầm rồi trấn áp. Thạch Hạo tuân theo lệnh của Thạch Hoàng nên không giết họ, nhưng vẫn khiến cả nhóm trọng thương và mất hết thể diện. Khi bị hỏi về nguồn gốc hộ tí, nó cố ý nói món đồ do một vị muội muội tặng, khiến mọi ánh mắt đổ dồn về Vân Hi và làm nàng vừa tức giận vừa xấu hổ. Cuối cùng, chủ nhân của Thanh Thiên bảo luân từ xa lên tiếng uy hiếp, nhưng Thạch Hạo chẳng những không nhượng bộ mà còn công khai thách đấu cả vị Tôn giả ấy lẫn con nhện lớn."},{"chuong":320,"tieuDe":"Tiểu Tổ Tông","tomTat":"Thanh Thiên tôn giả định giết Thạch Hạo ngay tại diễn võ trường, nhưng Luyện Thần đại trận của hoàng cung tự thức tỉnh, hóa thành tinh hải ngăn chặn bàn tay khổng lồ. Thạch Hoàng kiên quyết giữ tổ quy cấm sử dụng sức mạnh vượt cấp vương hầu trong hoàng cung, còn lão thị vệ trưởng cảnh cáo bất kỳ kẻ vi phạm nào cũng sẽ bị đại trận tiêu diệt. Không chịu núp dưới sự che chở, Thạch Hạo công khai thân phận truyền nhân Cung điện Chí Tôn, tố cáo Thanh Thiên tôn giả từng ban Thượng Cổ Thánh khí cho hậu nhân giết mình và tuyên chiến với cả lão lẫn Thái Cổ Ma Chu vì mối thù của tổ phụ. Thái Cổ Ma Chu thử dùng chân nhện công kích nhưng tiếp tục bị đại trận đẩy lui, khiến hai tôn giả đành tạm rút và hẹn quyết chiến với Thạch Hạo bên ngoài hoàng cung. Sau khi rời diễn võ trường, Thạch Hạo vẫn ung dung, từ chối lời khuyên dùng tấm da Hư Không thú để trốn khỏi Hoàng Đô của Hỏa Linh Nhi vì tin rằng mình có thể đánh bại hai cường địch. Khi Vân Hi và Ngân Tuyết tìm đến, cậu lập tức đề phòng họ muốn thu hồi hộ tí của Thần, đồng thời khẳng định sẽ không giao vật bảo mệnh ấy nếu bản thân còn bị đe dọa."},{"chuong":321,"tieuDe":"Uy Hiếp Sinh Linh Thuần Huyết","tomTat":"Vân Hi muốn đổi Thần Hành phù lấy hộ tí Thần linh và khuyên Thạch Hạo tránh giao chiến với hai tôn giả, nhưng hắn khẳng định tín vật đã thuộc về mình vì Thiên Thần sơn từng thất hứa, đồng thời chỉ chịu thương lượng nếu nàng bảo vệ Thạch thôn. Trước giờ quyết chiến, Thạch Hạo vẫn thản nhiên dự tiệc cùng Hỏa Linh Nhi, còn định nung Ma Chu thuần huyết trong chén Hóa Thiên nhưng phải giữ lại làm chủ dược luyện Thần đan vì độc tính quá mạnh. Khi hỏi con cháu Thái Cổ Thần Sơn về đối thủ, hắn biết tôn giả của Thanh Thiên Thần Sơn là một Thanh Loan thuần huyết trưởng thành, cũng là huyền tổ của Thanh Vân từng bị hắn ăn thịt ở Bắc Hải. Không hề e ngại, Thạch Hạo còn công khai tuyên bố sẽ giữ lại thân thể Thanh Loan làm thức ăn, khiến những người dự tiệc kinh hãi. Sau đó, Kim Chu của hồ Ma Linh dẫn theo một nhóm sinh linh thuần huyết trưởng thành tới chất vấn và đe dọa chặt hắn thành trăm khúc vì đã xúc phạm tổ phụ mình. Thạch Hạo chỉ bình thản đuổi Kim Chu sang một bên, bảo hắn chờ xem mình xử lý đại Ma Chu sau khi yến tiệc kết thúc."},{"chuong":322,"tieuDe":"Thiếu Niên Hung Tàn","tomTat":"Kim Chu nổi giận định giết Thạch Hạo ngay trước Thiên cung, nhưng thị vệ trưởng áo xám lập tức phong tỏa hư không và yêu cầu hai bên tới diễn võ trường phân thắng bại; ngay trong lúc ấy, Xám con bất ngờ xuyên qua phong ấn, cắn rách bảo y và làm Kim Chu bị thương. Biết Thái Cổ Kim Chu là sinh linh thuần huyết không độc, Thạch Hạo lập tức nhận lời giao chiến với ý định nếm thử thịt nhện. Tại diễn võ trường, cậu dung hợp hộ tí Thần Linh với Bất Diệt Kim Thân, dùng bảo thuật Toan Nghê nuốt lôi điện vàng rồi phản kích, đồng thời dựa vào nhục thân mạnh mẽ áp đảo Kim Chu trong cuộc đối quyền. Trước mạng nhện và xích thần trật tự của đối thủ, Thạch Hạo lần lượt thử sức thuật Côn Bằng, mở mười đại Động Thiên và vận dụng phù văn cơ bản trong Nguyên Thủy Chân Giải để phá tan mọi công kích. Cậu đánh Kim Chu gãy nhiều xương, buộc hắn hiện nguyên hình, bẻ gãy một chân nhện rồi dùng chén Hóa Thiên thu nhỏ và trấn áp hắn. Trở lại thọ yến, Thạch Hạo thản nhiên nướng chiếc chân Kim Chu bằng lửa phù văn, vừa ăn vừa uống rượu trước ánh mắt kinh hãi của toàn trường, còn hành động ấy cũng khơi dậy cơn thịnh nộ và lời đe dọa từ Thái Cổ Ma Chu. Sau đó, Nhân Hoàng phê chuẩn cuộc quyết chiến tiếp theo, khiến quảng trường cùng trung ương Thiên cung bay khỏi hoàng thành và hạ xuống giáo quân tràng trong sự chờ đợi của đám đông."},{"chuong":323,"tieuDe":"Diệt Ma Chu","tomTat":"Trung ương Thiên cung cùng quảng trường rời Hoàng thành, vượt qua hư không và giáng xuống giáo quân tràng, mang theo Nhân Hoàng, quần thần lẫn Thái Cổ Ma Chu. Trước sự uy hiếp của Ma Chu, Thạch Hạo vẫn thản nhiên ăn chân nhện vàng, còn cố ý mời Vũ tộc, Thạch Tử Đằng và các thiếu niên Thái Cổ Thần Sơn thưởng thức, rồi công khai khiêu chiến cả Ma Chu lẫn Thanh Loan tôn giả. Khi truy hỏi tung tích tổ phụ, cậu được thị vệ trưởng áo xám cho biết Đại Ma Thần tuy từng bị Ma Chu đánh trọng thương nhưng vẫn sống và đã tới vực ngoại tìm Thạch Tử Lăng. Ma Chu đồng thời nhận ra thị vệ trưởng chính là Kim Sí Đại Bằng từng can dự vào cuộc truy sát năm xưa. Đối mặt hai vị tôn giả đầy sát ý, Thạch Hạo giả vờ niệm chú triệu gọi chiến hồn và anh linh Cung điện Chí Tôn, nhưng thực chất âm thầm nhờ tiểu tháp ra tay và che giấu tung tích. Sau một thoáng im ắng, giáo quân tràng hiện lên bóng Thương Long, Chu Tước cùng vô số hung thú, rồi một cơn lốc phủ lông đỏ mang khí tức hung sát khủng khiếp xuất hiện. Thái Cổ Ma Chu kinh hãi gào thét nhưng không thể chống cự, cuối cùng bị cơn lốc đỏ hút vào trong và biến mất trước mắt mọi người."},{"chuong":324,"tieuDe":"Chém Tôn Giả","tomTat":"Thái Cổ Ma Chu bị lốc xoáy lông đỏ cùng bóng mờ của các cổ thú vây khốn, sau đó bị tiểu tháp tước sạch bảo vật, hút vào trong và luyện hóa hoàn toàn. Thạch Hạo mở mười Động Thiên tranh giành phần xác còn lại nhưng không thu được gì, đành tuyên bố trước mọi người rằng anh linh của Cung điện Chí Tôn đã tiêu diệt đối thủ. Thanh Loan tôn giả hoảng sợ bỏ chạy nhưng bị một sức mạnh vô hình kéo trở lại, buộc phải chủ động công kích Thạch Hạo để tìm đường sống. Tiểu tháp hiển hóa thần đài và biển thần lực màu vàng, đánh tan thần hà rồi trấn áp Thanh Loan, đồng thời cảnh báo Thạch Hạo rằng mỗi lần nó ra tay đều kéo theo nhân quả từ những cường giả liên quan hoặc thậm chí từ thiên địa. Thanh Loan tung Thanh Thiên bảo luân phản kích, song món Thánh khí vừa chạm vào tiểu tháp đã bị nuốt mất, khiến Thạch Hạo tiếc nuối vì chiến lợi phẩm tiếp tục rơi vào tay pháp khí. Khi Thanh Loan định tự bạo để ngọc đá cùng tan, tiểu tháp phóng ra hỗn độn kiếm xuyên thủng phù văn hộ thể, chém rơi đầu vị tôn giả và kết thúc trận chiến."},{"chuong":325,"tieuDe":"Trận Chiến Huy Hoàng Khép Lại","tomTat":"Tiểu tháp phóng hỗn độn kiếm mang chém chết Thanh Loan tôn giả rồi nuốt trọn thi thể để tu bổ những vết thương trên thân, khiến Thạch Hạo không giành được chiến lợi phẩm. Nó chỉ để lại một cọng nguyên thủy chân vũ chứa phù văn bẩm sinh, có thể phát ra kiếm khí mạnh mẽ và là một trong năm loại lông thần cần thiết để luyện chế quạt Ngũ Cầm. Biết đại sát khí thời Thượng Cổ này có uy lực thiêu hủy núi sông, Thạch Hạo liền nghĩ đến Hỏa Hồng và bắt đầu nuôi ý định thu thập đủ năm cọng chân vũ. Khi hắn trở lại giáo quân tràng một mình, quần hùng chấn động vì cả Ma Chu lẫn Thanh Loan đều đã biến mất, đồng nghĩa thiếu niên này vừa tiêu diệt hai vị tôn giả. Nhân Hoàng ban cho Thạch Hạo rượu đựng trong ly Cửu Long, một ân sủng hiếm có khiến các thế lực suy đoán hắn đã được lựa chọn làm người kế thừa. Giữa lúc danh tiếng Thạch Hạo lên đến đỉnh điểm, Thiên Hồ tiên tử vừa khen ngợi vừa tỏ ý đề phòng, còn Nguyệt Thiền tiên tử công khai tuyên bố hắn là đệ tử của Bổ Thiên giáo."},{"chuong":326,"tieuDe":"Hoang Thiên Hầu","tomTat":"Sau khi uống thần nhưỡng Cửu Long do Nhân Hoàng ban, Thạch Hạo suýt bước vào Minh Văn cảnh nhưng chủ động áp chế, phong kín dược lực trong máu thịt để tiếp tục tìm kiếm cực cảnh vượt trên cổ nhân. Nhờ chiến tích chém giết hai vị tôn giả, hắn được Thạch Hoàng sắc phong làm Hoang Thiên hầu, trở thành vương hầu trẻ tuổi nhất Thạch Quốc và bị đẩy lên đầu sóng quyền lực như một phép thử sinh tử. Danh tiếng của hắn khiến khách khứa kéo đến không dứt, còn những huynh đệ cũ của tổ phụ chuyển sang phủ Hoang Thiên hầu, khiến Võ Vương phủ chính thức phân liệt. Từ mẫu thân của Đại tiểu thư Lôi tộc, Thạch Hạo biết mẹ mình vốn xuất thân tại Huyền Vực, từng trở về bản tộc cầu thánh dược nhưng đến nay vẫn chưa quay lại. Vì Hoang Vực sắp đại loạn và giới vực bích sẽ khó vượt qua, hắn quyết tâm trước tiên quật khởi tại đây, rồi một ngày dùng thực lực mạnh mẽ quân lâm Huyền Vực để tìm cha mẹ. Sau khi lần lượt tiếp xúc với Hỏa Linh Nhi, Nguyệt Thiền và Thiên Hồ tiên tử, Thạch Hạo chuẩn bị rời Hoàng Đô, nhưng trước lúc đi đã công khai khiêu chiến Thạch Nghị, mở màn cho cuộc quyết đấu được mong đợi từ lâu."},{"chuong":327,"tieuDe":"Cổ Điện","tomTat":"Thạch Hạo công khai khiêu chiến Thạch Nghị, khiến Hoàng Đô chấn động và ân oán giữa hai thiếu niên Chí Tôn một lần nữa trở thành tâm điểm, nhưng Thạch Nghị vẫn chưa rời Thượng Cổ Thánh Viện để đáp chiến. Sau nửa tháng chờ đợi, Thạch Hạo để lại lời hẹn quyết đấu bất cứ lúc nào rồi bí mật rời Hoàng Đô, tránh khỏi những thế lực đang định dùng người liều chết thăm dò át chủ bài của mình. Nhờ Hỏa Linh Nhi kích hoạt da Hư Không thú, nó vượt qua hư không tới một cổ điện truyền tống giữa sa mạc Hỏa Quốc và bị người trong hoàng tộc hiểu lầm là nhân tài do nàng tuyển chọn. Mặc cho Thập Lục hoàng tử cùng hai công chúa chế giễu, Thạch Hạo không giải thích mà một mình tiến sâu vào vùng cơ duyên để đáp lại sự giúp đỡ của Hỏa Linh Nhi. Tam thúc tổ của hoàng tộc sau đó cảnh báo nơi này sắp xảy ra biến cố lớn, có thể khiến cả người Hỏa Quốc lẫn cường giả vực ngoại thương vong, trong khi mặt đất dưới chân Thạch Hạo bắt đầu nóng lên bất thường. Cùng lúc ấy tại di chỉ Bổ Thiên các, những vết nứt hư không báo hiệu Thạch Nghị sắp xuất quan, còn chủ hồ Ma Linh vẫn đích thân canh giữ để ngăn kẻ khác áp chế hắn khi vừa trở về."},{"chuong":328,"tieuDe":"Tổ Địa Của Hỏa Tộc","tomTat":"Giữa lúc Kim Chu âm thầm chuẩn bị cho đại loạn Hoang Vực, tin Thạch Nghị sắp rời Thượng Cổ Thánh Viện đã khiến thiên hạ xôn xao chờ đợi cuộc quyết đấu giữa hai thiếu niên Chí Tôn. Thạch Hạo một mình tiến sâu vào vùng sa mạc nóng bỏng, nơi dày đặc ao dung nham, hung thú và dấu vết của những cuộc giao tranh đẫm máu. Khi một nhóm quý tộc Hỏa Quốc cưỡi sói đỏ định ép nó làm mồi dò đường, Thạch Hạo đã dùng lôi điện áp đảo họ, đồng thời đánh lui sinh linh hung dữ ẩn dưới ao lửa. Từ những kẻ bị bắt, nó biết nơi đây chính là tổ địa thời Thượng Cổ của Hỏa tộc, chứa nhiều vật chất và sinh linh mang thần tính, từng giúp các đời Hỏa Hoàng nhanh chóng quật khởi. Việc các đại giáo vực ngoại chấp nhận hợp tác với Hỏa Hoàng để đổi lấy quyền đưa đệ tử vào càng chứng tỏ vùng đất này còn cất giấu cơ duyên phi phàm. Biết Thạch Nghị sắp xuất thế, Thạch Hạo quyết định lưu lại tu luyện, săn sinh linh thần tính và giao chiến với thiên tài vực ngoại để tự mình đột phá cực cảnh Hóa Linh, tiến vào Văn Minh cảnh mà không dựa vào tiểu tháp. Nó cũng được biết ngay cả Thần thời Thượng Cổ từng tới đây tìm kiếm một bí mật nào đó, còn Tế Linh từng bảo vệ Hỏa Quốc cũng được sinh ra tại chính vùng đất này."},{"chuong":329,"tieuDe":"Khu Vực Đỏ Đậm","tomTat":"Tại tổ địa Hỏa tộc, Thạch Hạo lần lượt săn giết những con vật bình thường đã lột xác thành hung thú, đồng thời phát hiện huyết nhục của chúng chứa vật chất thần tính có thể cường cân tráng cốt. Khi nó cùng nhóm tùy tùng tìm thấy một cây hoa sen xanh quý giá trong hẻm núi, một nhóm người cưỡi hung cầm bất ngờ tập kích, nhưng bảo cụ của họ bị Toan Nghê ấn đánh nát. Ngay sau đó, mặt đất trong phạm vi mười dặm sụp vỡ, dung nham đỏ đậm mang theo phù văn phun trào, chôn vùi toàn bộ những người xung quanh, chỉ Thạch Hạo kịp đạp bảo cụ thoát thân. Trên hồ dung nham vừa hình thành, một thiếu niên vực ngoại có cánh Phong Lôi ép Thạch Hạo xuống hái sen, song lại bị nó đánh bại và trấn áp sau hơn hai mươi chiêu. Khi bị ép tiếp cận mặt hồ, thiếu niên ấy bị một vòng xoáy cuốn xuống, vô tình làm lộ tòa thần phủ Thượng Cổ ẩn dưới đáy và cho thấy chính phù văn của nơi này đã gây ra tai biến. Biết thần phủ có thể giúp tăng tốc ngộ đạo, thậm chí cất giấu truyền thừa cổ xưa, hàng chục tu sĩ lập tức kéo đến tranh đoạt, còn Thạch Hạo cũng quyết định giành lấy cơ duyên tu hành này."},{"chuong":330,"tieuDe":"Thần Phủ","tomTat":"Bị một cường giả mọc cánh dùng tên bạc đánh lén, Thạch Hạo bắt lấy mũi tên rồi ném ngược, sau đó vận dụng bảo thuật Toan Nghê tiếp dẫn lôi điện để phản sát đối phương. Khi thần phủ hiện lên dưới hồ dung nham, nhiều người tranh nhau vượt qua phù văn trước cửa nhưng đều bị đánh bật, thậm chí có kẻ cưỡng ép xông vào đã hình thần câu diệt. Nhờ Trùng Đồng nhìn rõ bản chất thử thách, Thạch Hạo lựa chọn tổ hợp và thôi diễn cốt văn nguyên thủy để phá giải cửa ải. Một thiếu niên cánh hoàng kim đạt Minh Văn cảnh bất ngờ tập kích bằng lôi hải và tên vàng, song Thạch Hạo dùng bảo thuật Côn Bằng hấp thu lôi điện, đồng thời dẫn sức mạnh từ các mũi tên vào hệ thống phù văn để đẩy nhanh quá trình phá giải. Sau khi mở được đường, nó thu lấy hoa sen trước cửa rồi bước vào cổ điện, khiến cửa lớn khép kín và toàn bộ thần phủ chìm xuống đáy hồ dung nham, bỏ lại đám người bên ngoài. Trong kiến trúc Thượng Cổ tối tăm, Thạch Hạo phát hiện một chiếc đèn đồng bình thường còn lưu thần huyết chưa mất thần tính, bèn cất vào túi càn khôn rồi tiếp tục tiến sâu vào trong."},{"chuong":331,"tieuDe":"Đột Phá Cực Cảnh Ở Thần Điện","tomTat":"Thạch Hạo ăn hoa sen trắng bạc chứa sức mạnh thần tính, nhưng chủ động phong ấn dược lực vào huyết nhục và xương cốt để tránh tiến vào Minh Văn cảnh quá sớm. Ở nơi sâu nhất của đại điện, nó chỉ tìm thấy bồ đoàn phủ bụi, tro tàn, nửa trang bìa mang hai chữ “Chư Thần” và những tượng thần đã bị chém đầu, cho thấy truyền thừa cổ xưa đã bị phá hủy. Không thu được truyền thừa, Thạch Hạo quyết định tự tìm con đường vượt cực cảnh Hóa Linh từ Pháp và Đạo bằng cách nghiên cứu Nguyên Thủy Chân Giải, Bảo thuật Côn Bằng, cốt văn và thần hi. Nó thử rèn từng sợi thần hi thành những hình thái cụ thể rồi dùng chúng tái cấu trúc cốt văn, nhiều lần thất bại đến mức thổ huyết và suýt xé rách thân thể. Sau khi bước đầu thành công, nó phát hiện hình thái binh khí giúp tăng công kích, chuông và tháp tăng phòng ngự, còn lò lửa làm thần lực dâng cao. Thạch Hạo tiếp tục mở rộng phương thức diễn hóa sang sức mạnh tinh thần và dùng áp lực của thần hi để rèn luyện huyết nhục. Sau hơn nửa tháng, lượng biến dẫn đến chất biến, khiến thân thể, tinh thần, Pháp và Đạo của nó đồng thời lột xác và chính thức vượt qua cực cảnh Hóa Linh."},{"chuong":332,"tieuDe":"Thăng Hoa Đến Cực Điểm","tomTat":"Sau hơn mười ngày tu luyện trong đại điện ngộ đạo thời xưa, Thạch Hạo hoàn thành bước thăng hoa cực điểm của Hóa Linh và trở nên mạnh hơn trước rất nhiều. Đại điện nứt vỡ rồi sụp đổ ngay khi nó rời đi, khiến kế hoạch tiếp tục đột phá Minh Văn cảnh phải tạm hoãn. Vừa xuyên qua hồ dung nham, Thạch Hạo bị thiếu niên tóc vàng phục kích bằng những mũi tên hoàng kim để báo thù cho hai tôi tớ. Đối thủ đã bước vào Minh Văn cảnh và liên tiếp gia tăng thần lực, nhưng Thạch Hạo vẫn phá được hai mũi tên đầu bằng quang thuẫn cùng Bảo thuật Toan Nghê. Trước mũi tên thứ ba, nó vận dụng con đường mới lĩnh ngộ, biến từng sợi thần hi thành chuông nhỏ và nghiền nát đòn công kích. Thạch Hạo sau đó chuyển thần hi thành tiểu kiếm, áp sát phản kích và chém mất một mảng da đầu của thiếu niên tóc vàng."},{"chuong":333,"tieuDe":"Kẻ Chặn Đường Đều Chém","tomTat":"Thiếu niên tóc vàng của Phong Lôi Vũ tộc dốc toàn lực phản kích, liên tiếp vận dụng cánh Phong Lôi, thuật Lôi đạo và cung Phong Lôi Giao nhằm tiêu diệt Thạch Hạo. Trước mũi tên có uy lực của Minh Văn cảnh, Thạch Hạo tự diễn biến thần hi thành vô số đỉnh nhỏ, kết hợp thần thông Huyền Vũ rồi cộng hưởng với thiên địa để phá tan đòn công kích. Nó tiếp tục hóa thần hi thành chiến mâu, dùng cánh Côn Bằng vượt qua tám viên lôi châu và áp sát đối thủ, sau đó đánh nứt nắm tay, kéo đứt cánh tay rồi đá vỡ thân thể thiếu niên tóc vàng. Thạch Hạo đoạt cung Phong Lôi Giao và dùng chính bảo cụ này bắn chết toàn bộ đám tôi tớ đang lao tới cứu chủ. Khi hai thiên tài dị tộc ở Minh Văn cảnh xuất hiện ép giao cung, nó lập tức nghênh chiến, giết một kẻ sau hơn trăm hiệp rồi bắn trọng thương và chặt đầu kẻ còn lại đang bỏ chạy. Chiến tích liên tiếp ấy khiến những người chứng kiến chấn động, nhưng một biến cố lớn hơn đồng thời xảy ra tại di chỉ Bổ Thiên các: hư không rạn nứt, một thông đạo khó khăn mở ra và bóng người bí ẩn từ Thượng Cổ Thánh Viện bước ra ngoài."},{"chuong":334,"tieuDe":"Minh Văn","tomTat":"Tại di chỉ Bổ Thiên các, một cô gái áo xám mang khí tức tang thương và một thiếu niên Trùng Đồng lần lượt thoát khỏi thông đạo hư không hỗn loạn; khi nhện lớn màu vàng định nghênh chiến với cô gái, thiếu niên đã kịp thời ngăn lại. Ở tổ địa Hỏa Quốc, Thạch Hạo kiểm tra Cung Long Lôi Giao và nhận ra bảo cung có thể tiếp nhận, cộng hưởng mạnh mẽ với thần lực của mình. Nó sau đó bị bốn lão giả phạm giới dùng đèn bạc cùng cờ lớn truy sát, nhưng vì chưa rõ họ có thuộc Hỏa tộc hay không nên tránh giao chiến và dùng cánh Côn Bằng thoát đi. Tìm được một vùng hoang vắng, Thạch Hạo giải phóng tiềm năng cùng thần tính tích trữ, khiến phù văn thấm sâu vào huyết nhục, phủ tạng và xương cốt để kết thành chiến kén. Sau một ngày một đêm, nó hoàn thành đột phá từ Hóa Linh lên Minh Văn cảnh. Trước nguy cơ Hoang Vực đại loạn và áp lực từ một đối thủ sắp xuất thế, Thạch Hạo quyết định tiến sâu vào tổ địa để nhanh chóng nâng cao tu vi. Tại đây, nó nghe tin một tờ kinh văn cổ đã nhiều lần đổi chủ, khiến mọi người từng chiếm được đều bị sát hại và cuộc tranh đoạt vẫn tiếp tục nhuốm máu."},{"chuong":335,"tieuDe":"Một Tờ Kinh Thư","tomTat":"Thạch Hạo vốn không quá coi trọng kinh văn tàn khuyết vì đã nắm giữ Nguyên Thủy Chân Giải, nhưng vẫn theo đám đông đến hồ dung nham xem hơn nghìn người tranh đoạt. Khi một thiếu niên tóc tím thuộc tộc Viêm Mãng cố ép mình nhập cuộc, nó phát hiện đại trận phù văn đang được bí mật kích hoạt và lập tức cảnh báo mọi người. Huyết tế đại trận sau đó nghiền chết hàng chục người, hút huyết quang về hồ dung nham để mở Thượng Cổ Thánh Hoàng cung, khiến các lão giả vực ngoại phải truyền tin cầu viện Hỏa Hoàng. Một lá cờ vàng mang uy thế của Hỏa Hoàng giáng xuống phá tan sát trận, rồi tạo ra gió vàng chém chết những con Viêm Mãng đang hóa bản thể bỏ chạy. Sau khi đám đông nhận ra tờ kinh văn tranh đoạt chỉ là mồi nhử và tản đi, Thạch Hạo truy sát thiếu niên tóc tím, giao chiến hơn trăm hiệp rồi giết chết đối thủ dù cảnh giới của hắn cao hơn. Trong di vật của Viêm Mãng, Thạch Hạo tìm thấy một tờ kinh thư bằng đồng không bị nước lửa xâm hại, trên đó ghi lại phương pháp giúp nó nhanh chóng tăng thực lực ngay trong tổ địa, có giá trị còn lớn hơn một môn đại thần thông."},{"chuong":336,"tieuDe":"Phương Thuốc Cổ Xưa","tomTat":"Thạch Hạo giải đọc tờ kinh thư bằng đồng thau và phát hiện một phương thuốc cổ, có thể luyện sinh linh giàu thần tính trong Hỏa vực thành tinh hoa giúp ngộ đạo, phá quan và lột xác. Nhận ra giá trị của vùng đất này, nó quyết định tạm gác việc điều tra các thế lực đang âm thầm hoạt động để chuyên tâm nâng cao thực lực. Khi tiến sâu vào tổ địa Hỏa tộc, Thạch Hạo cứu Linh Phượng cùng nhóm thiếu niên khỏi một con trâu đen gần đạt cấp vương hầu, dùng cung Phong Lôi Giao và Bất Diệt Kim Thân chém chết hung thú. Nó đưa xác trâu vào chén Hóa Thiên, vận dụng đạo hỏa luyện thành một giọt chất lỏng thần tính màu vàng rồi nuốt xuống, khiến khí tức lập tức mạnh hơn. Hai ngày sau, Thạch Hạo tiếp tục săn một con sư tử bạc, thu thêm tinh hoa thần tính và giữ lại cốt tủy của hai hung thú để nghiền thành mồi nhử. Tại một hồ dung nham rộng lớn, bột cốt tủy đã dẫn ra một đàn cá vàng có linh tính sống giữa biển lửa, khiến nhóm thiếu niên vô cùng kinh ngạc và mở ra mục tiêu săn bắt quý hiếm tiếp theo."},{"chuong":337,"tieuDe":"Thạch Nghị Ứng Chiến","tomTat":"Sau khi xuất quan từ Thượng Cổ Thánh Viện của Bổ Thiên các, Thạch Nghị trở về Hoàng Đô và công khai đáp lại lời khiêu chiến của Thạch Hạo, khiến tin tức về cuộc quyết đấu giữa hai thiếu niên Chí Tôn nhanh chóng lan khắp Thạch Quốc và Đại Hoang. Trong tổ địa Hỏa Quốc, Thạch Hạo phát hiện đàn Cá mặt trời quý hiếm sống giữa hồ dung nham và dùng chén Hóa Thiên thu bắt, nhưng chỉ lấy được mười tám con vì bị một nhóm đệ tử đại giáo vực ngoại quấy nhiễu. Những kẻ này còn muốn cướp bảo vật và chủ động tấn công, buộc Thạch Hạo hợp nhất với Bất Diệt Kim Thân, phá hủy pháp khí rồi giết sạch đối phương. Thạch Hạo luyện số cá bắt được thành chất lỏng vàng chứa vật chất thần tính, sau đó tiếp tục đặt mồi thu gần trăm con để hấp thu tinh hoa và bế quan ngộ đạo. Thu hoạch này giúp tu vi của nó tiến bộ rõ rệt, đồng thời mở ra khả năng sớm bước vào Minh Văn cảnh trung kỳ. Cuối cùng, chiến tướng áo đen của Hỏa Linh Nhi tìm thấy Thạch Hạo và đưa nó tới gặp công chúa, nơi nàng báo tin Thạch Nghị đã trở về và cảnh báo rằng khí thế của hắn mạnh đến mức một lão bộc quan sát từ xa cũng phải run sợ."},{"chuong":338,"tieuDe":"Trùng Đồng Ước Chiến","tomTat":"Nghe Hỏa Linh Nhi thuật lại lời khiêu chiến công khai của Thạch Nghị, Thạch Hạo quyết định sẽ dùng một trận sinh tử công bằng để giải quyết mối thù Chí Tôn cốt, nhưng không chấp nhận để đối phương định đoạt thời điểm. Nó tạm tách khỏi Hỏa Linh Nhi, theo nhóm thiếu niên Hỏa tộc tới một hồ dung nham nguy hiểm để tìm cơ duyên tăng cường thực lực. Bằng cốt tủy của những sinh linh mạnh mẽ và thịt Viêm Mãng làm mồi, Thạch Hạo dụ được đàn Cá mặt trời xuất hiện rồi vận dụng Bát Hung kiếm trận, chén Hóa Thiên, bảo thuật Toan Nghê, Bất Diệt Kim Thân cùng mười đại Động Thiên để bắt sống hơn trăm con. Nó luyện cả đàn cá thành chất lỏng vàng giàu vật chất thần tính và quy tắc trật tự, bế quan nửa tháng rồi đột phá tới Minh Văn cảnh trung kỳ. Trong thời gian ấy, Thạch Nghị tiếp tục công khai ước chiến, tọa trấn Võ Vương phủ tụng kinh lắng đọng bản thân, sau một tháng lại tiến vào Hư Thần giới nghiên cứu những kỷ lục của tiền nhân. Nhận ra đối thủ đang gột rửa tâm linh và mài giũa thân thể trong một trạng thái tu hành cao thâm, Thạch Hạo đánh giá cách chuẩn bị ấy rất lợi hại và quyết định trở lại Hư Thần giới xem xét."},{"chuong":339,"tieuDe":"Cách Không Đối Lập","tomTat":"Sau hơn hai năm, Thạch Hạo trở lại Hư Thần giới, gặp Điểu gia và Tinh Bích đại gia tại Sơ Thủy Địa rồi để họ tung tin về lần tái xuất của mình. Tin tức thật giả đan xen nhanh chóng khuấy động các thế lực, nhưng những kẻ kéo đến dò xét đều hoảng sợ tháo chạy khi Thạch Hạo thực sự hiện thân. Thạch Hạo tiến vào khu vực Hóa Linh, trong khi Thạch Nghị cũng xuất hiện và dừng tại phúc địa Minh Văn, khiến vô số người đổ tới chờ xem hai thiếu niên Chí Tôn đối đầu. Chưa trực tiếp gặp mặt, hai người đã nhờ người truyền lời, lấy tình trạng của phụ thân đối phương để khơi lại những ân oán năm xưa. Thạch Nghị khắc lời nhận chiến lên nguyên thủy phù cốt, gửi theo uy thế nhằm thăm dò thực lực, nhưng Thạch Hạo bình thản hóa giải. Để đáp trả, Thạch Hạo lấy tấm biển đồng của phủ đệ Vũ tộc làm vật truyền lời, công khai chất vấn về Chí Tôn cốt từng bị đoạt. Thạch Nghị tuyên bố Chí Tôn cốt vẫn kém Trùng Đồng, còn Thạch Hạo phản bác rằng nếu thật sự tự tin vào Trùng Đồng, đối phương đã chẳng cần cướp cốt của người khác, đẩy cuộc ám chiến đến sát thời điểm bùng nổ."},{"chuong":340,"tieuDe":"Liên Tiếp Phá Kỷ Lục","tomTat":"Thạch Hạo công khai hẹn chiến với Thạch Nghị và yêu cầu đối phương trở lại Hóa Linh cảnh, trong khi Thạch Nghị ban đầu cho rằng nó chưa đủ tư cách, chỉ chấp nhận giao đấu tại Minh Văn cảnh. Để đáp lại sự khinh thường ấy, Thạch Hạo xông vào tịnh thổ Vũ tộc, đánh gãy bia công đức, phá hủy cung điện cùng đại trận bảo vệ bằng một cước và lập nên kỷ lục mới. Hai người sau đó liên tiếp phá kỷ lục tại hai khu vực cảnh giới, dùng bia đá của Hư Thần giới để truyền lời chất vấn và khiêu khích, khiến cả Hư Thần giới lẫn thế giới hiện thực chấn động. Thạch Hạo tiếp tục dùng trận đài đến khu vực Thái Cổ Thần Sơn, xông vào Hồ Ma Linh và triển khai mười Động Thiên cùng lực Côn Bằng để bóp nát tấm biển đồng thau từng được Thần Linh điểm hóa. Sau chiến tích này, nó lại dùng bia kỷ lục ép Thạch Nghị đưa ra câu trả lời dứt khoát. Cuối cùng, Thạch Nghị phá thêm một kỷ lục tại khu Minh Văn và ghi chữ “Chiến”, chính thức chấp nhận hạ xuống Hóa Linh cảnh để quyết đấu với Thạch Hạo."},{"chuong":341,"tieuDe":"Hồ Ma Linh","tomTat":"Sau khi liên tiếp phá kỷ lục để khiêu chiến Thạch Nghị, Thạch Hạo xông thẳng vào Hồ Ma Linh, phá hủy sơn môn và tuyên bố đôi bên đã là tử địch vì những ân oán với Vũ Vương Phủ. Nó đánh tan Vạn Chu Võng, đẩy lui một con nhện đen có huyết mạch gần thuần huyết, rồi đối đầu với nguyên lão nhện xanh đang điều khiển đại trận Thần Linh. Bằng hộ tí của Thần và sức mạnh mười Động Thiên, Thạch Hạo phá nát tầng trận pháp thứ nhất cùng một tòa Thiên cung, khiến trận kỳ tổ khí rời bỏ nhện xanh. Nó truy sát đối phương đang tháo chạy và xé đôi thân thể sinh linh thuần huyết ấy trong Hư Thần giới. Thạch Hạo tiếp tục dùng Diệt Hồn châm đánh vào thần hồn, khiến bản thể nhện xanh ngoài hiện thực gần như mất mạng, nhưng một con nhện vàng kịp ra tay cứu giữ tàn hồn. Khi Hồ Ma Linh kích hoạt tầng đại trận thứ hai để tiếp tục nghênh chiến, Thạch Nghị từ trên trời giáng xuống, ra lệnh dừng tay và bình tĩnh gọi Thạch Hạo là đệ đệ."},{"chuong":342,"tieuDe":"Kim Thân Bất Hoại","tomTat":"Sau nhiều năm xa cách, Thạch Hạo và Thạch Nghị tái ngộ tại hồ Ma Linh, mở đầu cuộc đối đầu giữa hai thiếu niên Chí Tôn. Thạch Nghị vận dụng Trùng Đồng tạo ra uy áp khủng khiếp, khiến nhiều người quan chiến bị thương và bảo cụ hộ thân vỡ nát, nhưng Thạch Hạo đã hóa đôi mắt, thần thức và thân thể thành chuông vàng để chống đỡ. Khi Thạch Nghị tuyên bố chưa phát huy sức mạnh chân chính, Thạch Hạo lấy con mắt Trùng Đồng của một thần nhân đã chết ra đáp trả, song đối phương cho rằng dị vật ấy chỉ còn một phần nhỏ uy lực. Hai người sau đó chuyển sang giao chiến bằng thân thể, liên tục va chạm dữ dội, phá hủy cấm chế và cảnh vật quanh hồ nhưng vẫn ngang sức ngang tài. Nguyệt Thiền và Ma Nữ nhận ra thân thể Thạch Nghị đã được Kim Thân dịch của Bổ Thiên giáo gột rửa, chứng tỏ hắn nhận được cơ duyên lớn tại Thượng Cổ Thánh Viện và có tư cách cạnh tranh địa vị tối cao trong giáo. Ma Nữ vì thế cảnh báo rằng nếu Thạch Nghị trở về Bổ Thiên giáo, hắn và Nguyệt Thiền có thể phải bước vào cuộc tranh vị khiến một người ngã xuống. Trong khi đó, Thiên Hồ tiên tử cùng Nguyệt Thiền xác nhận thân thể mạnh mẽ của Thạch Hạo hoàn toàn do hắn tự tu thành, không dựa vào Kim Cương dịch, khiến họ càng thêm chấn động và mong chờ diễn biến tiếp theo của trận chiến."},{"chuong":343,"tieuDe":"Cuộc Chiến Của Thiếu Niên Chí Tôn","tomTat":"Thể phách phi thường của Thạch Hạo và Thạch Nghị khiến các cường giả quan chiến chấn động, bởi cả hai đã sánh ngang chim thần và hung thú Thái Cổ dù Thạch Hạo chưa từng được Kim Cương dịch gột rửa. Hai thiếu niên liên tục đối đầu bằng quyền cước và phù văn, làm núi quanh hồ rạn vỡ nhưng vẫn giữ thế cân bằng. Thạch Nghị vận dụng thần lực cấm kỵ từ Trùng Đồng, còn Thạch Hạo tiến vào tâm cảnh nguyên sơ, khắc phù văn hình đỉnh trong máu thịt và xương cốt để phát huy sức mạnh phù hợp nhất với bản thân. Cú va chạm giữa họ tạm thời vượt qua cực hạn Hóa Linh cảnh, khiến quy tắc thiên địa và xích thần trật tự hiện ra, đồng thời làm cả hai trọng thương và chảy máu. Không ai chịu lùi bước, Thạch Nghị tiếp tục mở ra những phù văn tựa kinh cổ trong mắt, trong khi Thạch Hạo thu liễm ánh sáng và âm thầm tích tụ lực lượng cho đại thần thông. Đúng lúc trận chiến sắp bước vào cao trào mới, khí lành phủ kín vòm trời và một con đường màu vàng bí ẩn bất ngờ hạ xuống chiến trường."},{"chuong":344,"tieuDe":"Chiến Trường Thiên Không","tomTat":"Khi cuộc giao tranh giữa Thạch Hạo và Thạch Nghị có nguy cơ phá vỡ quy tắc cùng trật tự của Hư Thần giới, Vực Sứ giáng lâm và buộc hai người phải dừng tay. Thay vì rời đi hoặc chịu trục xuất, hai thiếu niên được phép tiến vào chiến trường Thiên Không, nơi từng dành cho cường giả cấp Thánh, Thần Linh và những sinh linh vượt qua cực cảnh quyết đấu. Vực Sứ còn tiết lộ nơi này liên quan đến chiến sự giữa các đại vực và võ đài cấp Thần, khiến mọi người lo ngại một thời kỳ đại loạn sắp mở ra. Thạch Hạo và Thạch Nghị được thông báo rằng chỉ người chiến thắng tại chiến trường Thiên Không mới có thể nhận những phần thưởng kỷ lục còn tồn đọng. Sau khi ấn định ngày mở chiến trường vào một tháng sau, Vực Sứ biến mất, còn hai đối thủ tiếp tục thăm dò nhau trong trạng thái chủ động kiềm chế sức mạnh. Cuộc giao đấu kéo dài gần nửa canh giờ và kết thúc khi cả hai cùng ho ra máu, để lại sự chấn động cùng niềm mong đợi về màn quyết chiến được xem là khởi đầu của cuộc chiến cấp Thần."},{"chuong":345,"tieuDe":"Tiến Hành Từng Bước","tomTat":"Sau cuộc giao chiến thăm dò bất phân thắng bại trong Hư Thần giới, Thạch Hạo trở về thân thể thật với thương thế tinh thần và lần đầu xem Thạch Nghị là đại địch thực sự. Tin tức về hai thiếu niên Chí Tôn nhanh chóng làm chấn động Hoang Vực, thu hút sự chú ý của các cổ quốc, Thái Cổ Thần Sơn cùng những thế lực vực ngoại như Bổ Thiên giáo, Tiệt Thiên giáo và Tây Thiên giáo. Trong lúc Thạch Nghị rời Vũ Vương Phủ, ung dung du ngoạn núi sông để mài giũa tâm cảnh và tiến tới cực cảnh Minh Văn, Thạch Hạo vẫn kiên định với con đường của mình, từng bước chuẩn bị cho trận quyết chiến sau một tháng. Nó săn hơn trăm con cá mặt trời, hấp thu vật chất thần tính trong chén Hóa Thiên để chữa lành, phá quan và tiếp tục cảm ngộ đạo tắc. Khi quan sát huyết nhục và xương cốt, Thạch Hạo thử tái cấu trúc thần hi thành thiên kiếm, lò thần, bảo đỉnh, rồi thành công cô đọng một sợi thần hi thành hình Côn Bằng thô sơ. Nó đặt mục tiêu biến toàn bộ thần hi trong cơ thể thành vô số Côn Bằng nhỏ, nhưng độ phức tạp của phù văn khiến con đường này vẫn cần thêm thời gian hoàn thiện. Giữa lúc Thạch Hạo đang bế quan, Hỏa Hoàng bất ngờ bước tới từ chân trời với uy thế khiến thiên địa rung chuyển, còn Hỏa Linh Nhi vội vàng đuổi theo phụ hoàng."},{"chuong":346,"tieuDe":"Ân Tình Của Hỏa Hoàng","tomTat":"Linh thân Hỏa Hoàng giáng xuống tổ địa Hỏa Tộc theo lời thỉnh cầu của Hỏa Linh Nhi, người đang lo Thạch Hạo gặp bất lợi khi tái chiến với Thạch Nghị chưa bộc lộ hết sức mạnh. Trước khi chỉ điểm, Hỏa Hoàng báo rằng thiên hạ sắp đại loạn và gửi gắm con gái cho Thạch Hạo bảo vệ khi hắn có đủ năng lực, còn Thạch Hạo trịnh trọng nhận lời. Nghe Thạch Hạo trình bày cách dùng thần hi hóa thành đỉnh, chuông và Côn Bằng để phá cực cảnh Hóa Linh, Hỏa Hoàng kinh ngạc nhận ra hắn đã sớm chạm tới vấn đề liên quan con đường thành Thần. Nhờ lời giải đáp ấy, Thạch Hạo xác định sẽ vừa khắc họa ký hiệu nguyên thủy vừa lĩnh hội hàm nghĩa sâu xa của Côn Bằng pháp. Hỏa Hoàng ban cho hắn một tòa phủ thần ẩn trong hồ dung nham, nơi có hiệu quả tu luyện vượt xa ngoại giới, khiến hắn ghi nhớ sâu sắc ân tình này. Kết hợp phủ thần với bồ đoàn gỗ Côn, Thạch Hạo tiến vào trạng thái ngộ đạo, chứng kiến cá đen và chim vàng tượng trưng cho âm dương, nhật nguyệt dung hợp thành Côn Bằng chân chính. Khi hoàn toàn hiểu thấu bảo thuật Côn Bằng, khí tức của hắn bùng phát dữ dội, làm cung điện cổ màu vàng rạn nứt rồi nổ tung."},{"chuong":347,"tieuDe":"Mồi Câu","tomTat":"Rời khỏi cung điện đổ nát dưới dung nham, Thạch Hạo xác nhận mình đã hoàn toàn lĩnh ngộ bảo thuật Côn Bằng, nhưng lần vận chuyển đầu tiên cũng cho thấy thần thông này tiêu hao quá lớn so với cảnh giới hiện tại. Nó nghi ngờ chiếc bồ đoàn trong cung điện đã giúp mình thấu hiểu phù văn nguyên thủy nhanh đến khác thường, đồng thời quyết định mau chóng nâng cao tu vi. Sau khi chứng kiến Bạch Giáp Vương dùng đá chứa vật chất thần tính để dụ giết một nhóm cường giả, Thạch Hạo ra tay áp đảo con hung thú Minh Văn hậu kỳ bằng thân thể mạnh mẽ và một phần lực lượng Côn Bằng, rồi bắt nó làm nguyên liệu câu Cá mặt trời. Dựa theo phương pháp ghi trong kinh văn, nó tiếp tục săn Chó ngao lông đỏ, Tê giác đen, Gấu lửa cùng nhiều sinh linh mạnh khác để phối thành mồi. Thạch Hạo còn tìm đến lãnh địa của Bọ ngựa cánh bạc, dùng lực lượng Thái Âm khống chế đôi đao sắc bén của nó và hạ sát hung linh sau một trận chiến dữ dội. Khi nhóm người tới hồ dung nham gần vùng cấm và thả thử một phần mồi, vô số Cá mặt trời màu vàng lập tức kéo đến thành đàn. Trước lượng con mồi vượt xa dự tính, Thạch Hạo tin rằng nếu bắt được toàn bộ, nó sẽ luyện ra đủ chất lỏng thần tính để đột phá Minh Văn hậu kỳ."},{"chuong":348,"tieuDe":"Thu Hoạch To Lớn","tomTat":"Thạch Hạo phát hiện hàng ngàn Cá mặt trời trong hồ dung nham, liền cùng các thiếu niên bố trí trận văn, bảo cụ và mồi nhử để thực hiện một mẻ bắt lớn. Dị tượng do đàn cá gây ra thu hút tộc một sừng, tộc bốn mắt và nhóm Nhân tộc vực ngoại kéo đến cướp đoạt, khiến đàn cá bạo động phản kích và giết gần nửa số người tham gia. Trong lúc hỗn loạn, Thạch Hạo mở mười đại Động Thiên, dùng chén Hóa Thiên thu hơn một nghìn con, còn Cá mặt trời vương sau khi giết một cường giả Minh Văn hậu kỳ đã tránh đối đầu với nó và dẫn đàn cá còn lại rút xuống đáy hồ. Ba phe sống sót quay sang bao vây, đòi chia chiến lợi phẩm, nhưng Thạch Hạo yêu cầu họ giao toàn bộ số cá và bảo cụ để bồi thường cho việc phá hỏng kế hoạch. Khi đối phương phát động lò đỏ rực trấn áp, nó thi triển bảo thuật Côn Bằng, hóa ra cá thần màu đen phá hủy bảo cụ, đóng băng và tiêu diệt phần lớn kẻ chống cự. Thạch Hạo đánh tan liên minh, giữ lại mỗi phe một người để thẩm vấn, đồng thời thu thêm năm sáu trăm Cá mặt trời cùng nhiều chiến lợi phẩm. Sau đó, nó dùng chén Hóa Thiên luyện đàn cá thành tinh hoa thần tính màu vàng, bế quan hấp thu và thành công đột phá tới cảnh giới Minh Văn hậu kỳ."},{"chuong":349,"tieuDe":"Xuất Quan","tomTat":"Thạch Hạo xuất quan sau khi đột phá Minh Văn hậu kỳ, thực lực, tinh thần và khả năng cảm nhận quy tắc trời đất đều tăng mạnh. Nó thẩm vấn ba thiên tài vực ngoại, thu được một số tin tức cùng tiểu thần thông, rồi giết cả ba khi cấm chế thần hồn khiến chúng không thể tiết lộ truyền thừa trấn giáo. Nhờ viên Trùng Đồng, Thạch Hạo tìm thấy đàn Cá mặt trời, đánh bị thương cá vương và bắt hơn một nghìn con, nhưng thần dịch luyện thành đã giảm tác dụng vì cơ thể nó sinh ra khả năng đề kháng. Sau khi chia thần dịch cho các thiếu nữ đồng hành và tặng phần lớn cho Hỏa Linh Nhi, nó biết hồ Ma Linh từng tập kích phủ Thiên Hầu nên tiến vào Hư Thần giới phá sơn môn đối phương để cảnh cáo. Thạch Hạo tiếp tục đến núi Thiên Thần, đối thoại với Vân Hi và tổ phụ nàng, qua đó biết họ chỉ thuộc một chi nhỏ của tộc Thiên Nhân, nhưng vẫn không chịu trả bao cổ tay của Thần Linh. Trở lại tổ địa Hỏa Quốc, nó tiến vào trung tâm cấm kỵ, tránh giao chiến với một con chim lửa đáng ngờ rồi tìm thấy cổ thụ khổng lồ mọc giữa miệng núi lửa. Trên tán cổ thụ, một tổ chim tỏa thần quang vàng rực và dao động mạnh đã thu hút Thạch Hạo trèo lên tiếp cận."},{"chuong":350,"tieuDe":"Chu Tước","tomTat":"Thạch Hạo trèo lên ngọn cây cổ thụ trong tổ địa và phát hiện một tổ chim vàng óng, bên trong cất giấu quả trứng đỏ như kim cương máu, tỏa sinh cơ mãnh liệt cùng sức nóng đủ nung chảy bảo cụ. Nó lấy quả trứng bỏ vào chén Hóa Thiên, vừa chống đỡ những đợt dao động khủng khiếp vừa phân vân nên ăn để lột xác hay ấp nở nhằm thu được bảo thuật Thái Cổ. Khi Thạch Hạo dùng phù văn kích thích, quả trứng bắt đầu nứt vỡ, cây cổ thụ cũng bùng phát đạo vận và vươn thẳng lên mây, còn một con chim đỏ nhỏ đầy phù văn chui ra rồi nuốt sạch vỏ trứng. Thạch Hạo giả làm phụ mẫu để lừa chim non, nhưng đối phương vẫn giữ nguyên trí nhớ sau khi niết bàn và chính là Tiểu Hồng từng xuất hiện ở thôn Thạch. Tức giận vì bị trêu chọc, Tiểu Hồng nhốt Thạch Hạo vào chén Hóa Thiên rồi dùng lửa nung suốt một canh giờ, chỉ dừng lại sau khi nó nhắc tới ân cứu mạng của Liễu Thần. Tiểu Hồng sau đó tiết lộ mình là Tế Linh đương nhiệm của Hỏa Quốc, còn Tế Linh Thượng Cổ là tổ mẫu của nó. Cuối cùng, lời Tiểu Hồng nói rằng con khỉ vàng đã mang Sơn bảo tới thôn Thạch khiến Thạch Hạo vô cùng chấn động."},{"chuong":351,"tieuDe":"Lai Lịch","tomTat":"Thạch Hạo nhận ra Sơn bảo chính là nguồn cơn của trận đại chiến giữa các cổ thú năm xưa, vì vậy dự định trở về thôn Thạch truy hỏi Mao Cầu và mời Tiểu Hồng điểu cùng nghiên cứu bảo vật. Qua lời Tiểu Hồng, cậu biết hỏa vực là hành cung duy nhất của Thái Cổ Chu Tước tại Hoang Vực, nơi vị thần điểu từng niết bàn, đồng thời biết tổ tiên của nó đã nhận được chân huyết Chu Tước và trở thành Thiên Thần. Sau khi không xin được đại thần thông hay bảo cụ, Thạch Hạo chuyển sang hỏi nguyên thủy chân vũ để tế luyện quạt Ngũ Cầm và được tiết lộ rằng trong Thánh Hoàng cung có thể còn lưu lại một cọng Chu Tước chân vũ. Tiểu Hồng cân nhắc mở đường vì Hỏa Hoàng đã hứa tặng một tia lửa Thần để Hỏa Linh Nhi được vào cung, còn Thạch Hạo đưa ra cơ hội tìm hiểu Sơn bảo làm điều kiện trao đổi. Hỏa Linh Nhi cảnh báo Thánh Hoàng cung là tuyệt địa đầy cấm chế, từ xưa rất ít người tiến vào có thể sống sót trở ra. Tiểu Hồng cũng tuyên bố nơi ấy hoàn toàn ngăn cách với ngoại giới, ngay cả Thiên Thần cũng không thể cứu viện, rồi mở một thông đạo lửa dẫn xuống tòa Thiên cung khổng lồ chìm nổi giữa dung nham."},{"chuong":352,"tieuDe":"Thánh Hoàng Cung","tomTat":"Thạch Hạo và Hỏa Linh Nhi men theo con đường lửa xuống biển dung nham dưới lòng đất, nơi Thánh Hoàng cung khổng lồ được pháp tắc không gian bảo vệ. Vì từng săn bắt Cá mặt trời, Thạch Hạo bị đàn cá nhận ra và cự tuyệt kết cầu hoàng kim dẫn đường, buộc cậu phải tự tìm cách tiếp cận cung điện. Vận dụng lĩnh ngộ về sự biến hóa của thần hi trong cảnh giới Hóa Linh, cậu cộng hưởng với các phù văn giữa hư không và dựng nên cầu thần bảy màu, thành tựu từng chỉ có Thánh Hoàng thời niên thiếu đạt được. Hai người vượt qua khoảng cách không gian, đặt chân tới cửa cung, còn đàn Cá mặt trời vì dè chừng tiềm lực của Thạch Hạo nên chủ động tránh xung đột. Hỏa Linh Nhi bước qua cửa thánh đầy nguy hiểm, chịu chân hỏa thiêu đốt mà không tổn thương, đồng thời xuất hiện dấu ấn Chu Tước nơi mi tâm, cho thấy huyết mạch của nàng đã thức tỉnh. Thạch Hạo nhận ra Thánh Hoàng cung vốn là nơi gột rửa huyết mạch Chu Tước cho Hỏa tộc, rồi tinh nghịch trêu chọc Hỏa Linh Nhi khi nàng còn mải vui mừng mà chưa nhận ra y phục đã bị thiêu rụi."},{"chuong":353,"tieuDe":"Dục Hỏa Luyện Kim Thân","tomTat":"Hỏa Linh Nhi vượt qua cửa thánh, được chân hỏa gột rửa và thức tỉnh dấu ấn Chu Tước nơi mi tâm, nhưng một sự cố y phục khiến nàng vừa xấu hổ vừa tức giận trước những lời trêu chọc của Thạch Hạo. Trong lúc né tránh sự truy đánh của nàng, Thạch Hạo vô tình kích hoạt thử thách cửa thánh và bị chân hỏa bao phủ. Không có huyết mạch Chu Tước hay thể chất Hỏa đạo, cậu phải dựa hoàn toàn vào thân thể cường đại để chịu đựng ngọn lửa thiêu thấu da thịt, phủ tạng và cốt tủy. Sau khi lớp da cháy đen bong ra, vật chất thần tính trong lửa bồi bổ cơ thể mới, giúp cậu hoàn thành việc tế luyện thân thể ở Minh Văn cảnh. Hỏa Linh Nhi kinh ngạc nhận định thành tựu dục hỏa luyện kim thân này có thể sánh với những cường giả mạnh nhất thời Thượng Cổ. Hai người tiếp tục tiến sâu vào Thánh Hoàng cung và nghe thấy tiếng tụng kinh chấn động hồn phách, được Hỏa Linh Nhi nhận ra là một bộ bảo kinh vô thượng thuộc Hỏa đạo."},{"chuong":354,"tieuDe":"Bốn Kích Của Thái Cổ Chu Tước","tomTat":"Trong Thánh Hoàng cung, Thạch Hạo và Hỏa Linh Nhi phát hiện một quyển kinh cổ được chuông đỏ cùng sức mạnh vô hình bảo vệ trên đạo đài nham thạch. Nhờ huyết mạch và truyền thừa Hỏa tộc, Hỏa Linh Nhi nhanh chóng cộng hưởng với Thánh Hoàng kinh, còn Thạch Hạo phải học phù văn cơ bản của Hỏa tộc mới có thể cảm nhận tạo hóa và lựa chọn con đường bảo thuật. Lựa chọn ấy kéo cậu vào ảo cảnh giao chiến với chim thần đỏ; khi thoát ra, cậu phát hiện mình đã đánh trúng chuông lớn và phải dùng bảo thuật Côn Bằng hóa giải lực phản chấn. Sau đó, bồ đoàn truyền thừa hút Hỏa Linh Nhi lên, đánh thức chân huyết và sức mạnh phù văn do Hỏa Hoàng phong ấn trong cơ thể nàng, khiến nàng có nguy cơ chìm vào giấc ngủ sâu. Cùng lúc, một sân đấu đá đen xuất hiện dành cho người ngoài Hỏa tộc, với phần thưởng là Bốn kích của Thái Cổ Chu Tước—thần thông chưa hoàn chỉnh nhưng cực kỳ bá đạo, đòi hỏi thể phách sánh ngang Chu Tước. Tin tưởng vào thân thể của mình, Thạch Hạo bước vào sân đấu, đối đầu Chu Tước đỏ rực do phù văn tạo thành và lập tức vận dụng Côn Bằng lực cùng mười đại Động Thiên, khiến toàn bộ khu vực thử thách chấn động như sắp sụp đổ."},{"chuong":355,"tieuDe":"Hồ Niết Bàn","tomTat":"Sau khi dốc hết sức vượt qua sân đấu màu đen, Thạch Hạo bước vào khảo nghiệm tiếp theo và dành hơn một tháng trong không gian thời gian đặc biệt của Thánh Hoàng cung để lĩnh ngộ bốn kích của Thái Cổ Chu Tước. Nhờ thân thể cường đại, nó nắm vững thần thông dương cương bá đạo này, rồi dùng một chưởng phá hủy cả bốn bia khảo nghiệm được luyện từ mảnh vỡ ngôi sao. Cùng lúc đó, Hỏa Linh Nhi hoàn tất tiếp nhận Thánh Hoàng kinh, khiến nhiều pháp môn lưu lại trong lòng và khí chất trở nên siêu thoát hơn. Hai người tiếp tục tiến sâu vào cung điện, cuối cùng phát hiện hai hồ dung nham mọc đầy sen vàng, bên trên nhỏ xuống chất lỏng đỏ thẫm pha ánh vàng. Hỏa Linh Nhi nhận ra đây là hồ Niết Bàn, được hình thành từ tinh hoa Thái Cổ Chu Tước để lại và từng giúp các đời tiên hiền Hỏa tộc lột xác mạnh mẽ. Nàng cảnh báo rằng người muốn vào hồ phải giữ thân thể thánh khiết và tế tự Chu Tước theo nghi thức cổ, nhưng những câu hỏi thiếu đứng đắn của Thạch Hạo lại khiến nàng nhớ chuyện cũ rồi nổi giận."},{"chuong":356,"tieuDe":"Chí Tôn Cốt Tái Sinh","tomTat":"Thạch Hạo và Hỏa Linh Nhi dùng nước Vô Trần gột rửa thân thể, sau đó tiến vào hai hồ Niết Bàn và cử hành cổ lễ tế tự Chu Tước Thái Cổ. Nghi thức khiến dung nham dâng trào sinh cơ, sen vàng nở rộ và giải phóng tinh hoa niết bàn để hai người hấp thu. Đả Thần Thạch cũng tỉnh lại sau thời gian dài tiêu hóa cát thần cùng đất Hỗn Độn, rồi nhảy xuống hồ tranh đoạt bảo dịch. Hỏa Linh Nhi được thần quang đỏ vàng bao phủ, kết thành một chiếc kén lớn và bắt đầu quá trình niết bàn. Khi quanh Thạch Hạo sắp hình thành kén, khí tức kinh thiên từ lồng ngực nó bất ngờ bùng phát, phá tan mọi luồng sáng và hút toàn bộ tinh hoa Chu Tước vào cơ thể. Huyết dịch Chí Tôn nhờ đó thức tỉnh, hội tụ thần tính từ huyết nhục, phủ tạng và xương cốt để tái tạo thành công một đoạn Chí Tôn cốt trắng bóng cỡ đốt ngón tay. Dù chưa trưởng thành hoàn toàn, khối cốt non trẻ đã tỏa ánh sáng đáng sợ và được bao quanh bởi quầng vàng rực rỡ như một mặt trời nhỏ."},{"chuong":357,"tieuDe":"Cốt Uy","tomTat":"Thạch Hạo nhận ra người tí hon sáng rực trong cơ thể là phù văn trên Chí Tôn cốt ngưng tụ thành, đại diện cho bảo thuật bẩm sinh độc nhất đang được khối cốt tái sinh thai nghén. Chí Tôn cốt điên cuồng hấp thu tinh khí của nó và tinh hoa thần tính trong hồ Niết Bàn, khiến hồ khô cạn còn thân thể nó trở nên khô héo, suy nhược. Khi Thạch Hạo cưỡng ép vận dụng khối cốt chưa trưởng thành, một luồng cốt uy xuyên thủng cung điện và làm rung chuyển quần thể núi lửa, nhưng phản chấn cũng khiến xương cốt nó gãy nát, mi tâm rạn nứt và thần hồn suýt lìa khỏi xác. Sau khi tỉnh lại, nó xác định bảo thuật Chí Tôn chính là con đường phù hợp nhất với mình, đồng thời nhận ra khối cốt niết bàn tái sinh hiện tại đã khác với Chí Tôn cốt từng bị Thạch Nghị chiếm đoạt. Thạch Hạo dùng rượu Hầu Nhi cầm cự rồi đánh lừa Đả Thần Thạch để giành huyết thanh niết bàn; qua nhiều ngày tranh đoạt thêm thần dịch, thương thế của nó hoàn toàn hồi phục và trạng thái trở lại đỉnh cao. Trong khi Hỏa Linh Nhi vẫn ngủ sâu trong kén để trải qua lần lột xác trọng yếu, Thạch Hạo thăm dò khu vực lân cận và phát hiện một dãy cửa đá cổ khắc các sinh linh hồng hoang. Hình Tỳ Hưu phát ra tiếng gầm khi bị chạm vào khiến nó chưa vội mở cửa, mà chuyển sang quan sát cánh cửa khắc Kim Sí Đại Bằng mang uy thế kinh hồn."},{"chuong":358,"tieuDe":"Bức Tường Thần Ma","tomTat":"Trong Thánh Hoàng cung, Thạch Hạo phát hiện một bức tường xám cổ xưa cao lớn như núi, có một trăm lẻ tám cửa đá chạm hình các sinh linh, nhưng những cửa mang hình Chân Long và Chu Tước lại không thể mở. Sau khi kiểm tra Hỏa Linh Nhi vẫn đang ở trong kén bên hồ Niết Bàn, cậu quay lại đẩy mở một cửa và bị đưa vào sân thi đấu màu đen, nơi ghi rằng chỉ kỳ tài thắng liên tiếp một trăm lẻ tám trận mới có tư cách bước lên con đường bí ẩn. Hơn trăm hung thú Minh Văn cảnh lập tức vây công theo chiến trận, song Thạch Hạo dùng phù văn của Nguyên Thủy Chân Giải phá tan thế trận rồi giết sạch chúng, khiến tất cả hóa về những tờ phù chú ố vàng và cháy thành tro. Tiếp đó, một con Chu Yếm Thái Cổ đầu bạc mang huyết thống thuần khiết xuất hiện trấn giữ sân đấu, trực diện lấy thể phách đối đầu với Thạch Hạo. Cú va chạm khiến Chu Yếm lùi ba bước nhưng không hề bị thương, qua đó cho thấy thân thể của nó mạnh mẽ đến đáng sợ. Đả Thần Thạch chạy tới, tiết lộ Chu Yếm nổi danh với bảy mươi hai biến và thuật luyện thể từng đủ sức xé rách Thần Ma, đồng thời ám chỉ bức tường hiếm khi hiện thế này có thể là một cơ duyên lớn, nhưng chỉ chịu xác nhận sau khi Thạch Hạo đánh bại đối thủ."},{"chuong":359,"tieuDe":"Bí Ẩn Hé Lộ","tomTat":"Trong sân thi đấu màu đen, Thạch Hạo giao chiến dữ dội với Chu Yếm do lá bùa vàng diễn hóa và chiếm ưu thế ngay cả khi đối đầu bằng thể thuật. Chu Yếm thi triển bảy mươi hai biến, hóa thành Thạch Hạo để mô phỏng biển sấm và bảo thuật Côn Bằng, nhưng chỉ tái hiện được hình thức chứ không nắm giữ tinh túy chân chính. Thạch Hạo dùng Đả Thần Thạch đánh đối thủ choáng váng, sau đó vận chuyển lực Côn Bằng, kết hợp sức mạnh Thái Âm và hình thái chim Bằng vàng để giết Chu Yếm, khiến lá bùa hóa thành tro. Sau trận chiến, Đả Thần Thạch tiết lộ thần thông và thuật luyện thể của nhất mạch Chu Yếm cực kỳ đáng sợ, đồng thời giải thích rằng đây là bức tường Thần Ma chưa hoàn chỉnh đầu tiên của Hoang Vực, nơi đặt ra chuỗi thử thách dành cho thiên tài tuyệt đỉnh. Không muốn mạo hiểm liên chiến toàn bộ một trăm lẻ tám sân đấu, Thạch Hạo chuyển sang khám phá cánh cửa đá khắc hình người chưa hoàn thiện. Bước vào sân đấu yên tĩnh phía sau cánh cửa, nó bất ngờ nhìn thấy chiếc thuyền giấy màu đen từng xuất hiện ở Bắc Hải đang từ từ hạ xuống."},{"chuong":360,"tieuDe":"Tôi Luyện","tomTat":"Thạch Hạo đối mặt với thuyền giấy đen thần bí, chống đỡ vô số phù văn và bảo thuật rồi phát hiện trên vách đá những hình khắc liên quan đến hai chữ “Hi Vọng” và “Trở Về”. Bất chấp lời cảnh báo của Đả Thần Thạch về sự biến mất của những sinh linh từng dính líu tới chiếc thuyền, cậu vẫn chọn bức tường Thần Ma làm nơi tôi luyện. Suốt một tháng trong Thánh Hoàng cung, Thạch Hạo liên tiếp huyết chiến với hàng chục sinh linh thuần huyết, vận dụng thập đại Động Thiên và pháp môn Côn Bằng, qua đó mài giũa bảo thuật, lĩnh ngộ phù văn và bắt đầu nảy sinh ý niệm sáng tạo pháp của riêng mình. Trong lúc ấy, Hỏa Linh Nhi phá kén niết bàn thành công, thức tỉnh toàn diện huyết thống Chu Tước và hiện ra đôi cánh ánh sáng đỏ rực. Nhờ đồng cảm với hang Chu Tước, nàng vượt qua trận pháp của Thánh Hoàng Thượng Cổ, tiến vào tu hành rồi lấy nguyên thủy chân vũ ném cho Thạch Hạo. Ba ngày sau, Hỏa Linh Nhi hoàn tất truyền thừa, cùng Thạch Hạo bước lên tế đàn ngôi sao và được truyền tống ra khỏi Thánh Hoàng cung."},{"chuong":361,"tieuDe":"Thiếu Niên Vực Ngoại Tụ Hợp","tomTat":"Sau khi rời khỏi nơi sâu nhất trong Hỏa vực, Thạch Hạo và Hỏa Linh Nhi nhận ra ngày càng nhiều thiếu niên vực ngoại đang xâm nhập khu cấm kỵ của Hỏa tộc để tìm kiếm cơ duyên. Biết Thạch Hạo quen Tế Linh Hỏa tộc, Hỏa Linh Nhi lớn tiếng xin bái sư, được Tiểu Hồng dùng chân hỏa kiểm tra, xác nhận đã thức tỉnh huyết mạch Chu Tước và ban cho một bộ vũ y quý giá. Tiểu Hồng đồng ý chỉ điểm nàng sau khi nàng trở về bẩm báo Hỏa Hoàng, rồi tiện chân đá Thạch Hạo bay xa vì thái độ thiếu kính trọng trước đó, nhưng nó kịp dùng cọng lông đỏ hấp thu hỏa diễm nên không bị thương nặng. Trên đường đi, đoàn người của Thiên Nhãn Thánh sơn chặn Hỏa Linh Nhi, muốn ép nàng bàn chuyện kết minh và thông gia nhằm đặt cược vào một Hoàng giả bản địa trước đại loạn Hoang Vực. Thạch Hạo tự nhận là huynh trưởng kiêm chiến tướng của nàng, một hơi thổi bay hơn mười cường giả trẻ tuổi, phá tan phù văn của các lão giả và đánh trọng thương thiếu chủ Tam Nhãn tộc. Sau chiến thắng, nó còn tuyên bố Nguyệt Thiền tiên tử là muội muội mình, đúng lúc nhóm nhân kiệt Bổ Thiên giáo xuất hiện phủ nhận và tiết lộ Nguyệt Thiền cũng đã tới Hỏa vực. Thạch Hạo vẫn thản nhiên đề nghị trực tiếp đối chất với nàng, khiến đám đông chấn động và một thiếu niên Bổ Thiên giáo lộ ánh mắt lạnh lẽo."},{"chuong":362,"tieuDe":"Đệ Tử Bổ Thiên","tomTat":"Tại tổ địa Hỏa tộc, một thiếu niên nòng cốt của Bổ Thiên giáo bất ngờ dùng Dẫn Long Thủ tấn công Thạch Hạo, nhưng bị hắn dùng phù văn nguyên thủy đẩy lui. Khi thân phận thiếu niên Chí Tôn của Thạch Hạo được nhận ra, các tu sĩ xung quanh đều kinh sợ, còn hắn cố ý khoe quan hệ thân thiết với Nguyệt Thiền để chọc giận đối thủ. Trước thế công mang hình thái chân long, Thạch Hạo thi triển bốn kích Chu Tước Thái Cổ, đánh thiếu niên kia chảy máu và buộc hắn phải dùng một phần Bổ Thiên thuật để gia trì chiến lực. Muốn quan sát bảo thuật trấn giáo hoàn chỉnh, Thạch Hạo chủ động giữ sức và khiêu khích thêm hai nữ đệ tử tham chiến, song vẫn dễ dàng áp đảo cả ba rồi thả họ ra. Chiến tích ấy khiến những thiên tài vực ngoại và sinh linh Thần sơn không còn dám xem thường Hoang Vực. Biết Nguyệt Thiền sắp đến, Thạch Hạo công khai ở lại chờ nàng, đồng thời tuyên bố muốn bắt nàng về thôn vì lo nàng có thể trợ giúp đại địch của mình trong tương lai."},{"chuong":363,"tieuDe":"Lựa Chọn","tomTat":"Nguyệt Thiền tiên tử tới tổ địa Hỏa quốc, được các nguyên lão long trọng tiếp đón và khiến những thiên tài vực ngoại cùng sinh linh thuần huyết đều phải dè chừng. Nàng đưa Thạch Hạo ra khu rừng bên ngoài để nói chuyện riêng, khuyên hắn dựa vào nguồn gốc truyền thừa của Bổ Thiên các mà gia nhập Bổ Thiên giáo, nhưng hắn phủ nhận quan hệ giữa hai thế lực. Nguyệt Thiền cảnh báo Hoang Vực sắp đại loạn, đồng thời tiết lộ Thạch Nghị đã trở thành đệ tử Bổ Thiên giáo và có cả một đại giáo chống lưng. Dù được hứa hẹn cơ hội trở thành truyền nhân mạnh nhất, thậm chí hiệu lệnh thế lực trải rộng nhiều vực, Thạch Hạo vẫn từ chối vì không muốn bị ràng buộc, cuốn vào tranh chấp giữa các đại giáo hay trở thành quân cờ của bất kỳ ai. Hắn khẳng định sẽ tự tranh đoạt và sáng tạo con đường của mình, càng không chấp nhận đứng chung một giáo phái với Thạch Nghị. Khi nhận ra không thể lay chuyển quyết định ấy, Nguyệt Thiền xác lập hắn là đối thủ của đệ tử bổn giáo rồi hỏi liệu hắn có sợ bị giết ngay tại đây để loại trừ hậu họa hay không. Thạch Hạo bình tĩnh mời nàng ra tay, còn Nguyệt Thiền hiện thần hoàn và chăm chú nhìn hắn, khiến khu rừng chìm vào bầu không khí căng thẳng như thể một trận chiến có thể bùng nổ bất cứ lúc nào."},{"chuong":364,"tieuDe":"Sát Cơ","tomTat":"Sau cuộc giằng co dưới ánh trăng, Nguyệt Thiền tiên tử vẫn để Thạch Hạo rời đi, đồng thời ngăn bà lão tùy tùng trực tiếp truy sát vì e ngại thủ đoạn từng giúp hắn giết hai vị tôn giả. Không chịu từ bỏ, bà lão âm thầm tính kế xác định hành tung của Thạch Hạo, mượn tay các cường giả khác và thậm chí tập kích thân thể thật của hắn khi hắn tiến vào Hư Thần giới quyết chiến với Thạch Nghị. Trở lại Hỏa vực, Thạch Hạo được Hỏa Linh Nhi vừa niết bàn thành công cùng linh thân Hỏa Hoàng cho mượn truyền tống trận để tới biên giới phía Tây Thạch Quốc, chuẩn bị trở về Thạch thôn. Bà lão dùng da Hư Không thú theo dõi gợn sóng truyền tống nhưng bị Hỏa Hoàng phát hiện và đánh trọng thương, chỉ kịp suy đoán phương hướng đại khái của hắn. Vì muốn giữ tuyệt mật tọa độ Thạch thôn, Thạch Hạo dừng lại ở nơi cách quê nhà ba trăm ngàn dặm rồi bắt một con thiên nga di chủng làm tọa kỵ. Trên đường, một thiếu niên cầm cung bất ngờ bắn chết thiên nga, suýt làm Thạch Hạo trúng tên, sau đó còn ngạo mạn sai hắn vặt lông con mồi. Trước sự ngang ngược ấy, Thạch Hạo nổi sát ý và trực tiếp tuyên bố đối phương đang tự tìm đường chết."},{"chuong":365,"tieuDe":"Ngông Nghênh Giết Sạch","tomTat":"Chứng kiến nhóm thiếu niên vực ngoại tùy tiện bắn chết một con thiên nga chỉ để làm thức ăn, lại không ngừng miệt thị sinh linh Hoang Vực, Thạch Hạo nổi giận và trực tiếp đối đầu với chúng. Một thiếu niên dùng sương mù ăn mòn cùng nhiều bảo cụ tấn công, nhưng không thể làm tổn thương thân thể Thạch Hạo, trái lại còn bị nó phá nát tấm chắn, hộ tí và đánh trọng thương. Trước sự vây công của cả nhóm, Thạch Hạo thi triển lực Côn Bằng, diễn hóa đại dương màu đen đánh bay sáu bảy đối thủ. Thủ lĩnh cầm cung đích thân giao chiến, song Thạch Hạo dùng Phong Lôi Giao bắn trả, khiến núi non tan vỡ và một số sinh linh vực ngoại chết dưới loạn tiễn. Sau khi hiện nguyên hình Hôi Giao thuần huyết và chiến đấu hơn một trăm hiệp, thủ lĩnh vẫn bị Thạch Hạo chém bay đầu, thi thể trở thành lễ vật nó định mang về Thạch thôn. Cùng lúc đó tại biên giới phía Tây, một nhân vật thần bí ngồi giữa thần hỏa cảm ứng được cái chết của Hôi Giao, qua đó hé lộ sinh linh thuần huyết chí cường này thực chất chỉ là tùy tùng của người ấy."},{"chuong":366,"tieuDe":"Thiên Hạ Hữu Địch","tomTat":"Trên đỉnh núi, một chàng trai thần bí đến từ vực ngoại nghe thuộc hạ báo cáo về hành tung của Nguyệt Thiền tại tổ địa Hỏa quốc, đồng thời bộc lộ ý định chiếm lấy cả linh thân lẫn trái tim nàng. Khi cảm ứng Hôi Giao đã bị một thiếu niên Hoang Vực chém đầu, hắn cảnh cáo đám sinh linh thuần huyết không được khinh địch, chỉ sai họ dò tìm tung tích đối phương để mình đích thân thu phục. Sau khi tiêu diệt Hôi Giao, Thạch Hạo bắn hạ những kẻ tháo chạy, bắt giữ số còn lại để thẩm vấn rồi kết liễu toàn bộ và thu thi thể làm chiến lợi phẩm. Biết phía sau chúng còn có một nhân vật trẻ tuổi vô cùng đáng sợ, nó nhận ra ngoài Nguyệt Thiền và Ma nữ, thiên hạ vẫn còn nhiều địch thủ mạnh mẽ. Để tránh nguy hiểm tại biên giới phía Tây, Thạch Hạo dùng Súc Địa phù phối hợp thân pháp Côn Bằng chạy xuyên Đại Hoang, nhanh đến mức bảo y hóa thành tro và khiến một con Anh Vũ chín màu kinh ngạc. Cuối cùng, nó nhìn thấy cây liễu lớn của quê nhà, trở về Thạch thôn và quyết định nhờ Liễu Thần bảo vệ thân thể để chân linh tiến vào Hư Thần giới đại chiến."},{"chuong":367,"tieuDe":"Gia Đình","tomTat":"Thạch Hạo trở về Thạch thôn sau nhiều tháng xa cách, được tộc nhân nồng nhiệt chào đón và mang thi thể Hôi Giao thuần huyết về bồi bổ cho mọi người. Nhờ linh khí dồi dào cùng nguồn tài nguyên quý giá, Thạch thôn đã phát triển mạnh, nhiều người tiến vào Động Thiên cảnh, còn Thạch Lâm Hổ, Thạch Phi Giao và Thanh Phong đều đạt Hóa Linh cảnh. Bữa tiệc Hôi Giao khiến tinh khí trong cơ thể đám trẻ bùng phát, đồng thời giúp Nhị Mãnh, cha Nhị Mãnh và Tị Thế oa lần lượt đột phá. Trước trận quyết chiến, Thạch Hạo không tiếp tục khổ tu mà hoàn toàn thả lỏng bên gia đình, bạn cũ và những sinh linh thân thuộc của quê nhà. Nó cũng biết nhóm Bóng Lông vẫn chưa tìm thấy thần tàng Chí Tôn vì bảo tàng dưới lòng đất đã lẩn trốn. Khi trò chuyện với Liễu Thần, Thạch Hạo được xác nhận pháp môn Côn Bằng là thần thuật cái thế, đồng thời biết Liễu Thần còn một pháp môn khác sẽ truyền cho nó sau khi trận chiến kết thúc và cảnh giới phù hợp hơn. Trong lúc Thạch Hạo tận hưởng những ngày bình yên cuối cùng, toàn Hoang Vực và Hư Thần giới đã sôi sục chờ cuộc đối đầu giữa hai thiếu niên Chí Tôn tại chiến trường Thiên Không sau ba ngày nữa."},{"chuong":368,"tieuDe":"Hứng Thú Trẻ Con","tomTat":"Trong buổi sáng thanh bình tại Thạch thôn, Thạch Hạo luyện bớt tinh hoa thần tính trong thịt giao rồi chia cho đám trẻ, sau đó bị chúng vây quanh và khơi lại hàng loạt chuyện nghịch ngợm thuở nhỏ. Dù chỉ còn ba ngày nữa phải vào Hư Thần giới quyết chiến, hắn vẫn chọn thả lỏng tâm cảnh, dẫn bọn trẻ vào Đại Hoang tìm tổ chim và thú non. Cả đoàn phát hiện tổ chim tước năm màu được kết bằng nhiều lá linh dược kỳ lạ, chạm trán rắn bay, ổ chồn tím và cứu một con chồn non ba mắt đang hấp hối bằng rượu Hầu Nhi. Tiến sâu hơn, họ bắt gặp một lân báo biến dị và một Thiểm Điện Khuyển cùng chết sau trận ác chiến, nhờ đó tìm thấy bốn Thiểm Điện Khuyển con và quyết định mang chúng về nuôi làm thú bảo vệ thôn. Trong khi ấy, nhóm Bì Hầu không tìm được hang lân báo nhưng đã giao chiến rồi tha cho một hắc hùng tinh biết quỳ lạy cầu xin. Đến khi mặt trời lặn, đám trẻ đều vui vẻ trở về với trứng chim hoặc thú con, còn tại một dãy núi khác, Trùng Đồng giả một mình bước lên đỉnh cao, lặng lẽ nhìn khắp non sông."},{"chuong":369,"tieuDe":"Bão Táp Nổi Lên","tomTat":"Thạch Hạo cùng đám trẻ đưa hàng loạt dị chủng non về Thạch thôn, tin rằng với Thanh Lân Ưng, Đại Hồng Điểu và Liễu Thần trấn giữ, chúng sẽ được thuần dưỡng ổn thỏa. Chỉ còn hai ngày trước trận quyết chiến, nó không tiếp tục khổ tu mà vui đùa bên lửa trại, tự tay hầm thịt hung thú và tìm lại tâm cảnh vô tư thuở nhỏ. Trong khi đó, Thạch Nghị lần theo cổ thư tìm tổ địa Thạch tộc nhưng đi lệch khỏi Thạch thôn, rồi trên đường trở về đã dùng một đòn tiêu diệt hơn mười dị chủng cùng đại trận Ly Hỏa. Chiến tích ấy khiến thiếu niên bí ẩn ngồi giữa lửa thần chú ý; kẻ này quyết định tới Hư Thần giới xem trận đấu, bắt cả hai thiếu niên Chí Tôn và còn coi Nguyệt Thiền là mục tiêu hàng đầu. Khi Thạch Nghị trở lại Võ Vương phủ, thánh chỉ của Thạch Hoàng phong hắn làm Vô Song hầu đã gây chấn động Thạch Quốc, bởi phong hiệu ấy được xem là đặt hắn ngang hàng với Hoang Thiên hầu Thạch Hạo. Nhìn thấy chữ “Nhân” ở mặt sau thánh chỉ, Thạch Nghị chỉ cười nhạt rồi nghiền ý chỉ thành bột, sau đó dùng pháp khí luyện từ phù cốt Hư Không thú mở thông đạo tới hồ Ma Linh để âm thầm tiến vào Hư Thần giới. Trước giờ quyết chiến, bão táp đã nổi lên khi Chiến trường Thiên Không không chỉ thu hút hai đối thủ mà còn kéo theo nhiều kẻ mang dã tâm riêng."},{"chuong":370,"tieuDe":"Ngày Quyết Chiến","tomTat":"Thạch Nghị được pháp khí xuyên thời không đưa về hồ Ma Linh, nơi hắn được các ma chu nghênh đón và dẫn vào Thiên cung trung ương. Nhện vàng, sư thúc của hắn, tin chắc Thạch Nghị sẽ đánh bại Thạch Hạo nên đã gửi thiệp khắp các Thái Cổ Thần Sơn, chuẩn bị yến tiệc mừng ngôi vị thiên hạ đệ nhất từ trước trận đấu. Dù mang niềm tin vô địch, Thạch Nghị vẫn giữ thái độ thận trọng, trong khi dư luận phần lớn nghiêng về phía hắn nhờ Trùng Đồng, Chí Tôn cốt tái tạo và thân thể đã được Kim thân dịch hoàn thiện. Đến ngày quyết chiến, vô số sinh linh cùng các Tôn giả, bá chủ và Hoàng giả đổ vào Hư Thần giới, khiến võ đài chiến cấp Thần trở thành tâm điểm của toàn Hoang Vực. Thạch Nghị dẫn nhân mã hồ Ma Linh xuất hiện với khí thế áp đảo, còn Hỏa Hoàng, Thạch Hoàng, Hoàng giả Mộc tộc, Hải tộc, Ma nữ và nhiều cường giả khác lần lượt giáng lâm quan chiến. Khi Thạch Hạo mãi chưa tới, đám đông bắt đầu nghi ngờ hắn sợ chiến, ngay cả Vực Sứ cũng công khai lên tiếng thúc giục. Đúng lúc ấy, một thông đạo rực rỡ bất ngờ mở ra ngay sau Vực Sứ, buộc ông ta phải tránh đường, rồi Thạch Hạo ung dung bước ra trước ánh mắt sững sờ của toàn trường."},{"chuong":371,"tieuDe":"Mở Ra Chiến Trường Phủ Đầy Bụi","tomTat":"Thạch Hạo vượt qua biển người bằng một thông đạo hư không bí ẩn và bất ngờ xuất hiện sát bên Vực Sứ, khiến vị sứ giả kinh hãi, thậm chí nghi ngờ một vị thần từng kiến tạo Hư Thần giới vẫn còn sống. Trước sự thúc giục của Thạch Nghị và thái độ thù địch từ hồ Ma Linh, Vực Sứ mở đại lộ màu vàng, đưa hai huynh đệ lên vùng thiên ngoại cổ xưa, trong khi rất nhiều người quan chiến không chịu nổi uy thế dọc đường nên buộc phải bỏ cuộc. Chiến trường Thiên Không phủ bụi nhiều năm được mở lại, hiện ra như một võ đài cấp Thần có quy tắc bảo hộ và kích thước thay đổi theo cảnh giới của người quyết đấu. Phần đông người xem cho rằng Thạch Nghị nắm bảy đến tám phần thắng nhờ Trùng Đồng và thực lực toàn diện, nhưng những người ủng hộ Thạch Hạo vẫn tin thiếu niên từng sống sót sau khi mất Chí Tôn cốt có thể tiếp tục tạo nên kỳ tích. Khi trận chiến bắt đầu, hai người lao vào nhau như những ngọn núi cổ va chạm, tạo ra thần quang và sóng xung kích dữ dội; qua lần đối đầu đầu tiên, Thạch Nghị nhận ra thể phách của Thạch Hạo đã mạnh hơn, còn Thạch Hạo phát hiện đối thủ từng dùng Kim thân dịch luyện thể. Khí thế đôi bên tiếp tục dâng cao khi Thạch Nghị đánh ra tử khí từ lòng bàn tay, còn Thạch Hạo dựng lên ánh lửa đỏ rực và dùng ký hiệu cổ xưa để trực diện nghênh kích."},{"chuong":372,"tieuDe":"Chu Tước Vs Kỳ Lân","tomTat":"Trên Chiến trường Thiên Không, Thạch Hạo và Thạch Nghị mở màn cuộc quyết đấu bằng những đòn cận chiến nhanh và dữ dội, thể hiện sức mạnh của hai thiếu niên Chí Tôn. Thạch Nghị thi triển Kỳ Lân bộ, tích lũy uy thế qua từng bước và đến bước thứ bảy đã ép Thạch Hạo lùi lại, khóe miệng rỉ máu, song truyền thừa Kỳ Lân của hắn bị nhận định là chưa hoàn chỉnh. Thạch Hạo lập tức dùng bốn kích Chu Tước phá thế áp chế, áp sát phản công và đánh Thạch Nghị văng đi, khiến đối phương cũng phải thổ huyết. Hai người tiếp tục hợp nhất với pháp tướng Kỳ Lân tím và Chu Tước đỏ, tạo nên cú va chạm làm võ đài nứt vỡ, phá hủy hơn mười lớp rào chắn và buộc Vực Sứ tự mình tu bổ. Khi trở lại hình người, Thạch Hạo đẩy thể thuật cùng bốn kích Chu Tước đến cực hạn, tiếp tục áp đảo và đánh Thạch Nghị phun máu. Tuy nhiên, thắng bại vẫn chưa thể xác định vì Thạch Nghị chưa vận dụng năng lực mạnh nhất của Trùng Đồng, khiến nhiều người tin rằng hắn vẫn có cơ hội đảo ngược thế trận."},{"chuong":373,"tieuDe":"Cuộc Chiến Giữa Hai Người Mang Họ Thạch","tomTat":"Cuộc đối đầu giữa bốn kích Chu Tước thái cổ và Kỳ Lân thuật đã đánh thức những chiến hồn bất hủ từng bỏ mạng trên võ đài chiến cấp Thần, buộc Thạch Hạo và Thạch Nghị vừa giao tranh vừa tiêu diệt các anh linh cản đường. Thạch Nghị thi triển chuỗi tuyệt sát gồm bánh xe Kỳ Lân và tám bước Kỳ Lân bộ, làm chiến trường Thiên Không tan hoang rồi đá trúng vai Thạch Hạo, khiến đối thủ phun máu và để một cánh tay mềm rũ. Tưởng rằng Thạch Hạo đã gãy xương, hắn lập tức truy sát, nhưng không ngờ đó chỉ là kế giả thương dụ địch dựa trên thân thể cường đại của đối phương. Thạch Hạo bất ngờ phản kích, vận chuyển bốn kích Chu Tước thái cổ đến mức xuất thần nhập hóa, liên tiếp đánh Thạch Nghị lõm ngực, gãy xương và ho ra máu. Sự đảo chiều khiến những người từng tin kết cục đã định đều biến sắc, còn Thạch Hạo tiếp tục đạp bước trên hư không và tung một cước dữ dội nhằm vào đối thủ. Bị dồn vào thế nguy hiểm, Thạch Nghị vận dụng thần thông cấm kỵ của Trùng Đồng, phóng luồng sáng đen từ mắt phải làm cả chiến trường rung chuyển, khiến tất cả nín thở chờ xem Thạch Hạo có thể chống đỡ hay không."},{"chuong":374,"tieuDe":"Uy Lực Của Trùng Đồng","tomTat":"Thạch Nghị phô bày thần năng đáng sợ của Trùng Đồng khi mắt phải phát ra ánh đen hủy diệt rào chắn, còn mắt trái tỏa sinh cơ giúp thương thế và xương cốt nhanh chóng phục hồi hoàn toàn. Sau khi tuyên bố trước đó chưa thật sự vận dụng sức mạnh thiên phú, hắn tái chiến với Thạch Hạo, khiến cuộc đối đầu trực diện giữa hai người càng thêm dữ dội. Thạch Hạo diễn hóa bảo thuật Toan Nghê, ngưng tụ mười ngôi sao sấm sét trong lòng bàn tay, nhưng Thạch Nghị nhờ Trùng Đồng nhìn thấu biến hóa nên kịp thời né tránh, để đòn đánh phá hủy một phần lớn chiến trường Thiên Không. Với khả năng phân giải mọi động tác và cảm nhận chuyển động của đối thủ như chậm lại, Thạch Nghị liên tiếp hóa giải sát chiêu, phản kích chính xác rồi đánh Thạch Hạo bay vào lan can, miệng phun máu. Chiếm được ưu thế, Thạch Nghị kết hợp Trùng Đồng với bảo thuật Kim Sí Đại Bàng, đẩy tốc độ lên cực hạn và hóa bàn tay vàng thành đòn chém nhằm lấy đầu đối thủ. Không chịu khuất phục, Thạch Hạo dồn sức tăng tốc, hóa thành một luồng cầu vồng lao thẳng tới, mở màn cho cuộc va chạm tuyệt sát chưa phân thắng bại."},{"chuong":375,"tieuDe":"Cực Tốc","tomTat":"Thạch Hạo vận dụng cực tốc của bảo thuật Côn Bằng, phá vỡ ưu thế quan sát của Trùng Đồng, né sát chiêu rồi xé bảo y và chém cánh tay Thạch Nghị bị thương sâu tới xương. Thạch Nghị dùng ánh sáng từ mắt trái chữa lành vết thương, đồng thời nhận ra đối thủ có thể đã đoạt được tạo hóa Côn Bằng tại Bắc Hải và âm thầm nảy ý định chiếm lấy. Sau hàng loạt đợt giao phong nhanh đến cực hạn, Thạch Nghị triển khai thiên địa hỗn độn để giam cầm thân thể, trung hòa tốc độ của Thạch Hạo, rồi liên tiếp diễn hóa Bệ Ngạn và mặt trời vàng trấn áp. Thạch Hạo chủ động từ bỏ ưu thế tốc độ, kết hợp thân thể mạnh mẽ với cốt văn của Nguyên Thủy Chân Giải để đánh vỡ mặt trời vàng. Tuy nhiên, những mảnh phù văn không tiêu tán mà tái hợp thành một chiếc chuông vàng, để Thạch Nghị mượn chính thần lực của đối thủ rèn nên đạo binh ngay giữa trận chiến. Trước sóng âm làm chấn động thần phách và phá hủy rào chắn chiến trường, Thạch Hạo vận chuyển phù văn Toan Nghê cùng Chu Tước, cưỡng ép tiến tới và liên tục dùng quyền công kích thân chuông. Khi kinh văn hiện lên trên chuông vàng và tiếng tụng niệm vang động trời đất, ngay cả các Tôn giả cũng phải chăm chú chờ xem cuộc đối đầu giữa thân thể Thạch Hạo và đạo binh Thạch Nghị sẽ dẫn tới kết quả nào."},{"chuong":376,"tieuDe":"Thiên Kiêu Quyết Chiến","tomTat":"Thạch Hạo chống lại bí pháp luyện thần của chuông vàng, hóa thân thành kiếm rồi đánh nát thân chuông, nhưng lập tức rơi vào sát cục Kim Ô do Thạch Nghị âm thầm thai nghén bên trong và bị liên hoàn trọng thương. Khi Thạch Nghị định thừa thế truy sát, Trùng Đồng cảnh báo nguy hiểm giúp hắn kịp rút khỏi phạm vi thập đại Động Thiên mà Thạch Hạo chuẩn bị mở để phản kích. Thạch Hạo sau đó thăng hoa Toan Nghê bảo thuật thành một tinh hà lôi điện, dùng nhật nguyệt và vô số sao lớn vây ép đối thủ đến mức chiến trường Thiên Không đứng trước nguy cơ đổ nát. Thạch Nghị dùng Trùng Đồng khai thiên tạo ra vùng tịnh thổ ngăn cản sấm chớp, song vẫn bị sát chiêu của Thạch Hạo biến thành cá đen mang dấu vết Côn Bằng xuyên thủng phòng ngự, đánh nứt xương ngực. Nhận ra Côn Bằng thuật, Thạch Nghị nảy sinh ý định chiếm đoạt, còn Thạch Hạo vận chuyển lực lượng cùng thân pháp Côn Bằng đến cực hạn để áp sát. Dù bị tia sáng hủy diệt từ mắt phải của Thạch Nghị sượt qua khiến máu chảy đầm đìa, Thạch Hạo vẫn liên tiếp phá thế phòng thủ, đánh thương cánh tay rồi đá lõm lồng ngực đối thủ, khiến hắn hộc máu và văng xuyên qua những khối đá lớn trên chiến trường."},{"chuong":377,"tieuDe":"Thần Thông Ra Hết Quyết Sinh Tử","tomTat":"Thạch Hạo áp đảo Thạch Nghị trong cuộc cận chiến, nhưng sức mạnh sáng tạo của Trùng Đồng nhanh chóng chữa lành thương thế và ngưng tụ chiến giáp bảo vệ đối thủ. Thạch Nghị lần lượt vận dụng bảo thuật Kim Ô và tiểu thế giới hoang vu để trấn phong, luyện hóa Thạch Hạo, song đều bị bảo thuật Côn Bằng phá tan. Hắn tiếp tục phóng hai khí âm dương tượng trưng cho hủy diệt và sáng tạo, đồng thời dùng Bổ Thiên thuật đối kháng, buộc Thạch Hạo phải mở thập đại Động Thiên và công khai thi triển trọn vẹn truyền thừa Côn Bằng. Sự kết hợp giữa côn ngư Thái Âm, chim bằng Thái Dương và mười Động Thiên khiến Thạch Nghị ho ra máu, liên tục thoái lui giữa chiến trường Thiên Không đang sụp đổ. Tuy nhiên, Thạch Nghị bất ngờ dùng phù văn Trùng Đồng hóa thành hai chiến mâu vàng, xuyên thủng tay trái và ngực Thạch Hạo rồi chuẩn bị kích nổ chúng. Thạch Hạo lập tức cấm phong khu vực bằng thập đại Động Thiên và vận chuyển sức mạnh Côn Bằng để phản kích, nhưng ngay sau đó cổ hắn bị cắt đứt, máu phun lên cao, khiến kết cục sinh tử vẫn còn bỏ ngỏ."},{"chuong":378,"tieuDe":"Vá Trời (Bổ Thiên)","tomTat":"Thạch Hạo dùng pháp môn Côn Bằng gần như chém lìa cổ Thạch Nghị, nhưng Bổ Thiên thuật đầy đủ đã đảo ngược tử cục, khiến máu chảy ngược và thương thế của hắn hoàn toàn khép kín. Sau khi Thạch Hoàng xác nhận đây là Chí Tôn thuật có thể bù đắp điều đã mất, song Thạch tiếp tục giao chiến dữ dội đến mức phá hủy chiến trường Thiên Không, buộc Vực Sứ phải triệu ra một đấu trường màu đen kiên cố hơn. Thạch Nghị bộc lộ mười Động Thiên mang hình thái các sinh linh thái cổ chí hung, đồng thời phối hợp Bổ Thiên thuật, Trùng Đồng và nhiều bảo thuật để đối đầu với thập đại Động Thiên hợp nhất cùng pháp môn Côn Bằng của Thạch Hạo. Trong cuộc giằng co đẫm máu, Thạch Hạo kéo đứt một cánh tay đối thủ nhưng cũng suýt bị chiến kích phù văn chém đôi, rồi dốc hết sức tung quyền xuyên thủng lồng ngực Thạch Nghị. Thạch Nghị dùng sức mạnh Trùng Đồng giữ thân thể không nổ tung, khiến cả hai rơi vào tình trạng lưỡng bại câu thương, gần như cùng chết. Trước hồi quyết định, Thạch Nghị tuyên bố sẽ dùng chính Chí Tôn cốt từng bị lấy khỏi Thạch Hạo để kết liễu cậu, còn Thạch Hạo lạnh lùng cảnh cáo rằng hắn chỉ đang tự tìm đường chết."},{"chuong":379,"tieuDe":"Thượng Thương Kiếp Quang","tomTat":"Thạch Hạo và Thạch Nghị mang thương thế gần như trí mạng nhưng vẫn dốc toàn lực bước vào cuộc đối quyết cuối cùng, khiến chiến trường Thiên Không cấp Thần cũng rạn nứt. Thạch Nghị vận dụng Chí Tôn bí lực và tiết lộ đã dùng Bổ Thiên thuật tế hóa khối Chí Tôn cốt lấy từ Thạch Hạo, khiến nó dung hợp hoàn mỹ với cơ thể mình. Từ khối cốt ấy, hắn phóng ra thần quang tương tự Thượng Thương kiếp quang, bao phủ võ đài bằng sức hủy diệt khiến các Tôn giả và Hoàng giả đều cho rằng thắng bại đã định. Tuy nhiên, Thạch Hạo vẫn đứng bất diệt giữa kiếp quang và công khai khẳng định mình mới là chủ nhân nguyên thủy của khối cốt, còn Thạch Nghị chỉ là kẻ cướp đoạt. Trước sự chấn động của quần hùng, Chí Tôn cốt đã niết bàn trong ngực Thạch Hạo bị kích thích thức tỉnh, làm thân thể Động Thiên bùng lên thần quang cùng vô số cốt văn. Thạch Hạo phá nát sân đấu, mang theo uy thế Chí Tôn áp sát Thạch Nghị; trong ánh sáng nhấn chìm mười phương, đám đông chỉ kịp thấy một thân thể bị xé rách và nghe tiếng kêu thảm, còn kết cục cuối cùng vẫn chưa được xác nhận."},{"chuong":380,"tieuDe":"Chém Trùng Đồng Giả","tomTat":"Sau khi võ đài bị phá hủy, Thạch Nghị mất một tay và một chân, đồng thời kinh hãi nhận ra Chí Tôn cốt của Thạch Hạo đã tái sinh và áp chế khối cốt từng bị cướp đoạt trong cơ thể mình. Vực Sứ thay sân đấu bằng một võ đài cấp Thần làm từ mảnh vỡ ngôi sao, còn Thạch Hạo tiếp tục dùng bí lực Chí Tôn cốt đánh nứt thân thể rồi xuyên thủng đối thủ. Không chấp nhận thất bại của Thạch Nghị, Kim Chu bí mật phóng lông nhện thần linh ám sát Thạch Hạo, trong khi Tích Hoa bà bà sai Chung lão dùng cấm khí thượng cổ thi triển nguyền rủa linh hồn. Dù nhất thời mất thần và suýt bị Thạch Nghị phản kích, Thạch Hạo nhanh chóng tỉnh lại, dùng thần uy Chí Tôn cốt hóa giải ám toán và khóa chặt đối thủ đã kiệt sức. Thạch Nghị vẫn tuyên bố mình không thua kém bất kỳ ai và cố vận dụng áo nghĩa tối cao của Trùng Đồng, nhưng thương thế quá nặng khiến hắn không thể thi triển trọn vẹn. Thạch Hạo tung chưởng phá hủy một con mắt của Thạch Nghị, sau đó đồng thời kích phát Chí Tôn cốt, Diệt Hồn châm và Trần Hồn tháp, đánh hắn nổ tung và chết ngay trên võ đài."},{"chuong":381,"tieuDe":"Khen Thưởng Phong Phú","tomTat":"Sau khi Thạch Nghị bị chém chết, con mắt Trùng Đồng còn sót lại hóa thành điện quang rồi nổ tung, xuyên thủng thân thể Thạch Hạo, nhưng không thể thay đổi kết cục cuộc chiến song Thạch. Chiến thắng của Thạch Hạo phá vỡ thần thoại bất bại của Trùng Đồng giả, khiến tin tức nhanh chóng truyền khắp Hư Thần giới, các Cổ quốc và toàn Hoang Vực. Vực Sứ nổi giận trước hành vi can thiệp chiến trường, dùng bàn tay khổng lồ tiêu diệt nhóm cường giả từng điều khiển lông nhện vàng, khiến Kim Chu chỉ có thể nhẫn nhịn. Trong lúc Thạch Hạo điều tức vì gân cốt và phủ tạng đều tổn thương nghiêm trọng, Hư Thần giới ban cho nó ba mảnh sách thần đồng thau, bao gồm cả phần thưởng vốn thuộc về Thạch Nghị, nâng tổng số mảnh nó sở hữu lên tám. Kho báu này cùng trạng thái trọng thương của Thạch Hạo khiến Kim Chu, Tích Hoa bà bà và nhiều Tôn giả nảy ý định cướp đoạt, trong khi một thiếu niên thần bí đứng giữa lửa thần cũng cân nhắc nhập cuộc. Nguyệt Thiền nhận ra biến động, mỉm cười kỳ lạ rồi biến mất, còn Thạch Hạo vẫn đứng giữa sân đấu, bình thản chuẩn bị đại khai sát giới nếu bất kỳ kẻ nào dám ra tay."},{"chuong":382,"tieuDe":"Chàng Trai Bên Trong Lửa Thần","tomTat":"Sau khi Thạch Nghị tử trận, Thạch Hạo dù được ca tụng như một thần thoại sống vẫn rơi vào hiểm cảnh vì trọng thương và bị nhiều cường giả nhòm ngó các miếng đồng thau trên người. Trong lúc nó vận chuyển thần hi hóa thành những lò lửa vàng để chữa thương, một chàng trai thần bí bao phủ trong lửa thần bất ngờ giáng xuống, thử bắt giữ rồi ngỏ ý thu phục nó vì tiềm năng và bảo thuật Côn Bằng. Thạch Hạo cự tuyệt, sẵn sàng nghênh chiến, nhưng đối phương tạm chuyển mục tiêu khi phát hiện Nguyệt Thiền tiên tử đang ẩn trong hư không. Chàng trai ngang nhiên tuyên bố muốn nàng đi theo mình và dùng ánh đỏ từ thần nhãn tiêu diệt hoàn toàn những người trẻ tuổi lên tiếng bảo vệ nàng. Nguyệt Thiền trách hắn ma tính quá nặng, còn hắn khẳng định thuận theo bản tính mới là căn nguyên của sức mạnh và chỉ chấp nhận để chính nàng độ hóa. Khi lời nói không thể lay chuyển Nguyệt Thiền, hắn đồng thời thi triển sáu loại bảo thuật như lục đạo luân hồi, buộc nàng rút thanh kiếm thần bằng ngọc thạch nghênh chiến, mở màn cuộc đại chiến dữ dội giữa ma và tiên trên chiến trường Thiên Không."},{"chuong":383,"tieuDe":"Hỗn Loạn","tomTat":"Chàng trai thần bí trong lửa thần hợp nhất sáu loại thần thông thành sáu tiểu thế giới, ép Nguyệt Thiền phải vận dụng thần kiếm trong cơ thể cùng áo nghĩa thâm sâu của Bổ Thiên giáo để đối kháng. Hắn cố ý đưa trận chiến ra khỏi chiến trường Thiên Không, công kích cả Vực Sứ rồi để chân hỏa lan vào đám đông, khiến nhiều tu sĩ thiệt mạng và hàng loạt Tôn giả bị cuốn vào cuộc hỗn chiến. Giữa lúc ấy, Thạch Hạo đang trọng thương trở thành mục tiêu của những kẻ thèm muốn sách quý đồng thau và nghi ngờ nó nắm giữ pháp môn Côn Bằng. Kim Chu bí mật liên kết các Tôn giả Thái Cổ Thần Sơn để vây giết Thạch Hạo, còn Tích Hoa bà bà sai Chung lão chuẩn bị nguyền rủa mạnh nhất nhằm đoạt cả tính mạng lẫn ấn ký bản nguyên của nó. Trước những đòn đánh lén luân phiên từ hư không, Thạch Hạo thi triển thần thông Huyền Vũ để phòng ngự, đồng thời dùng phù văn trong mắt tìm kiếm kẻ chủ mưu. Nó quyết định giết một người để răn đe quần địch, lập tức chọn Kim Chu làm mục tiêu vì mối thù với hồ Ma Linh từ đại chiến song Thạch. Kim Chu không dám đối đầu mà quay lưng bỏ chạy, còn Thạch Hạo hóa thành tia chớp đỏ thẫm, triển khai bốn kích Chu Tước thái cổ truy sát."},{"chuong":384,"tieuDe":"Tế Sống","tomTat":"Biết người đứng ngoài không có ý giúp đỡ, Kim Chi đành nghênh chiến, còn Kim Chu thi triển tơ nhện dung hợp máu tế luyện và thi độc thượng cổ để đối phó Thạch Hạo. Thạch Hạo dùng bốn kích Chu Tước thái cổ thiêu đốt tơ độc, áp sát bằng thân thể cường đại, đánh nứt chân nhện, phá tan khiên vàng và chặt đứt một chân của đối thủ. Bị dồn vào đường cùng, Kim Chu triển khai Bát Chu trận của hồ Ma Linh nhất mạch, dùng mạng nhện vàng, ký hiệu và xích thần trật tự phong tỏa thiên địa. Thạch Hạo chủ động tiến vào trận, hiện ra thập đại Động Thiên và vận dụng pháp môn cấm kỵ, cưỡng ép Động Thiên của Kim Chu cộng hưởng rồi thiêu đốt, biến chính đối thủ thành tế phẩm. Khi Bát Chu trận hóa thành tro, tia chân linh cuối cùng của Kim Chu cũng bị Trấn Hồn tháp trấn diệt, còn tinh hoa thần tính thu được liên tục tẩm bổ cơ thể và giúp Thạch Hạo dần hồi phục thương thế. Cảnh tượng một thiếu niên trọng thương vẫn tế sống được Tôn giả khiến các giáo phái kinh hãi, trong khi Tích Hoa bà bà nhận ra tiềm lực có thể ảnh hưởng vận mệnh đại giáo của hắn và nảy sinh sát ý vì hắn không thuộc Bổ Thiên giáo."},{"chuong":385,"tieuDe":"Kiếm Ý Của Thánh Nhân","tomTat":"Sau trận quyết chiến với Thạch Nghị, Thạch Hạo mang theo thương thế trầm trọng do Chí Tôn cốt chưa hoàn thiện phản phệ, cưỡi bảo kính Toan Nghê tìm đường rời khỏi Hư Thần giới giữa vòng vây của nhiều Tôn giả có địch ý. Khi một kẻ ẩn trong đám đông dùng nhà lao chín chữ cổ tập kích, nó vận dụng tiểu thế giới trong lòng bàn tay phá giải, đồng thời đoạt lấy một tia đạo ấn để uy hiếp những kẻ đang âm thầm ra tay. Một Tôn giả khác tế ra tấm da thú chứa kiếm ý thánh nhân, khiến Thạch Hạo phải dùng bốn kích Chu Tước, thập đại Động Thiên và pháp môn Côn Bằng chống lại kiếm quang cùng lực hút từ tiểu thế giới bên trong. Trong khoảnh khắc suýt bị thu vào da thú, nó nhìn thấy hai chữ “Lục Đạo”, sau đó đánh tan kiếm ý và trấn áp bảo vật, khiến chủ cũ kinh hãi vì huyền bí chưa từng bộc lộ. Các Tôn giả vẫn tiếp tục bào mòn Thạch Hạo bằng nhiều đòn đánh lén, trong đó sức mạnh nguyền rủa suýt chém tan thần hồn nó, nhưng thân thể Động Thiên đã tự phát hộ chủ và hóa giải công kích. Nhận ra Tích Hoa bà bà là kẻ đứng sau cuộc tập kích, Thạch Hạo bất chấp thương thế hóa thành Côn Bằng hình người lao tới, khiến kim quang trong cuồng phong biến thành bàn tay lớn tát bà ta bay xa, hộc máu và rụng răng trong kinh hãi lẫn phẫn nộ."},{"chuong":386,"tieuDe":"Tôn Giả Cùng Ra Tay","tomTat":"Sau khi công khai vạch trần và ra tay với Tích Hoa bà bà, Thạch Hạo truy kích nhưng bà ta đã dùng da Hư Không thú ẩn vào hư không, đồng thời kêu gọi các Tôn giả hợp lực trấn áp nó. Nhiều cường giả lập tức tập kích bằng tên vàng, ô đen và đủ loại bảo thuật, khiến nhiều tu sĩ vô tội thiệt mạng, còn Thạch Hạo bị thương nặng trong vụ nổ do ô đen tự hủy. Tiếng chuông bí ẩn tiếp tục dẫn động sức mạnh nguyền rủa đánh thẳng vào thần hồn, song Thạch Hạo đã vận dụng pháp môn diễn hóa thần hi thành những đỉnh nhỏ để hóa giải đòn công kích vô hình. Hỏa Linh Nhi cầu xin phụ hoàng cứu viện, nhưng Hỏa Hoàng từ chối can thiệp vì muốn Thạch Hạo tự vượt qua sát cục và chứng minh tư chất chân long. Giữa vòng vây, Thạch Hạo dùng thần thức tìm ra Tôn giả cầm cung, thi triển pháp môn Côn Bằng phá tan các đòn cứu viện, xé nát cung vàng, giật đứt một cánh tay rồi xé xác đối thủ sau hơn trăm chiêu ác chiến. Nó còn dùng Trấn Hồn tháp diệt sạch chân linh của kẻ địch, khiến bản thể ngoài hiện thực cũng mất mạng, sau đó vận chuyển Nguyên Thủy Chân Giải để dò tìm Tích Hoa bà bà đang ẩn trong hư không."},{"chuong":387,"tieuDe":"Càn Quét","tomTat":"Dù trọng thương và liên tục bị tiếng chuông nguyền rủa công kích tâm thần, Thạch Hạo vẫn một mình chống lại cuộc hợp kích của nhiều Tôn giả bằng cách luyện hóa Tiên Thiên Ly Hỏa, vận dụng Chu Tước bảo thuật và chén Hóa Thiên để hóa giải các pháp khí. Nó tiếp tục dùng sức mạnh Côn Bằng phá tan bảo thuật Cùng Kỳ, Thiểm Điện Ưng Chuẩn, rồi diễn biến Nguyên Thủy Chân Giải để đánh nát thuyền Quỷ Thần đang ăn mòn tinh khí thần. Khi Tích Hoa bà bà dẫn thêm sáu, bảy Tôn giả công khai vây giết và Chung lão lập đàn thi triển lời nguyền mộc nhân, Thạch Hạo dựa vào hộ tí thần linh tranh thủ tích tụ toàn bộ sức mạnh. Nó đồng thời mở thập đại Động Thiên cùng huyết nhục Động Thiên, đẩy pháp môn Côn Bằng tới cực hạn, dung hợp sức mạnh Thái Âm và Thái Dương để quét ngang chiến trường, giết ba Tôn giả và khiến lời nguyền phản phệ Chung lão. Dù phải trả giá bằng lượng thần lực khổng lồ và nhiều đoạn xương gãy thêm, Thạch Hạo vẫn dùng Diệt Hồn châm kết liễu những kẻ đã ngã xuống. Thấy đại thế đã mất, Tích Hoa bà bà dùng da Hư Không thú ẩn vào hư không bỏ chạy, nhưng bị Thạch Hạo phong cấm không gian, cưỡng ép kéo ra ngoài rồi xách lên và liên tục tát đến răng máu văng tung tóe trước sự kinh hãi của mọi người."}];
